  exclusions: string[];
  db_mode: 'insert-only' | 'upsert';
}

export interface PVRecord {
  id: string;
  source: 'pubmed' | 'web';
  pmid?: string;
  doi?: string;
  title: string;
  authors?: string[];
  journal?: string;
  year?: string;
  dp?: string;
  edat?: string;
