                            <div className="bg-indigo-50 p-2 rounded">
                              <span className="block text-gray-500">MedDRA PT</span>
                              <span className="font-bold">{record.pv_data.meddra_pt_candidate} ({record.pv_data.meddra_confidence}%)</span>
                            </div>
                            <div className="bg-indigo-50 p-2 rounded">
                              <span className="block text-gray-500">嚴重性</span>
                              <span className="font-bold">{record.pv_data.seriousness}</span>
                            </div>
                            <div className="bg-indigo-50 p-2 rounded">
                              <span className="block text-gray-500">劑量途徑</span>
                              <span className="font-bold">{record.pv_data.dosage_route}</span>
                            </div>
                            <div className="bg-indigo-50 p-2 rounded">
                              <span className="block text-gray-500">因果關係</span>
                              <span className="font-bold">{record.pv_data.causality}</span>
                            </div>
