          {activeTab === 'database' && (
            <div className="space-y-4">
              <h2 className="text-2xl font-bold text-gray-800">系統執行日誌</h2>
              <div className="bg-gray-900 text-green-400 font-mono text-sm p-4 rounded-lg h-[600px] overflow-y-auto">
                {logs.length === 0 ? (
