                ) : (
                  logs.map((log, i) => <div key={i} className="mb-1">{log}</div>)
                )}
              </div>
            </div>
          )}
        </section>
      </main>

      {/* Suggestion Footer for Extra Features */}
      <footer className="bg-gray-100 border-t p-4 text-xs text-gray-500">
        <div className="max-w-6xl mx-auto grid grid-cols-3 gap-8">
          <div>
            <h4 className="font-bold mb-1 text-gray-700">建議新增功能 (1)</h4>
            <p>串接 MedDRA 官方 API 做精準術語對齊，降低 CIOMS 生成的人工校對時間。</p>
          </div>
          <div>
            <h4 className="font-bold mb-1 text-gray-700">建議新增功能 (2)</h4>
