import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY;

export class PVGeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY! });
  }

  async scoreRelevance(records: any[]) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Evaluate the pharmacovigilance (PV) relevance of these literature records. 
      Input records: ${JSON.stringify(records)}
      Instructions: Score 0-100. High scores for case reports, clinical trials showing new AE, or regulatory alerts. Low scores for general reviews or unrelated contexts.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING }
            },
            required: ["id", "score", "reason"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  }

  async generateSummaries(records: any[]) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `你是一位專業的藥品安全監視 (PV) 專員。請為以下文獻提供繁體中文摘要。
      要求：
      1. 重點說明提到的藥品/成分與不良反應 (AE)。
      2. 如果原文內容非常短（例如只有標題），請嘗試根據標題解讀潛在風險。
      3. 若真的無法從內容推斷任何 PV 訊息，請回傳 "無法從現有資訊產出摘要"。

      文獻列表： ${JSON.stringify(records)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              summary_zh: { type: Type.STRING }
            },
            required: ["id", "summary_zh"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  }

  async extractPVData(record: any) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Extract structured PV data from this abstract: ${record.abstract}. Align with MedDRA PT if possible.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            product: { type: Type.STRING },
            ingredient: { type: Type.STRING },
            ae_verbatim: { type: Type.STRING },
            meddra_pt_candidate: { type: Type.STRING },
            meddra_confidence: { type: Type.NUMBER },
            seriousness: { type: Type.STRING },
            population: { type: Type.STRING },
            dosage_route: { type: Type.STRING },
            tto: { type: Type.STRING },
            outcome: { type: Type.STRING },
            causality: { type: Type.STRING },
            completeness: { type: Type.STRING }
          },
          required: ["product", "ae_verbatim", "meddra_pt_candidate", "completeness"]
        }
      }
    });
    return JSON.parse(response.text);
  }

  async generateCIOMS(record: any, pvData: any) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a CIOMS I draft mapping based on this record: ${JSON.stringify(record)} and extracted PV data: ${JSON.stringify(pvData)}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            patient_initials: { type: Type.STRING },
            country: { type: Type.STRING },
            reaction_description: { type: Type.STRING },
            suspect_drug: { type: Type.STRING },
            daily_dose: { type: Type.STRING },
            event_onset_date: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text);
  }
}

import React, { useState, useCallback, useMemo } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  InformationCircleIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['Drug X', 'Brand Z'],
    active_ingredients: ['Ingredient A', 'Ingredient B'],
    date_window: { from: '2024-01-01', to: '2024-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'side effect', 'drug-induced', 'toxicity'],
    optional_ae_focus_terms: ['hepatotoxicity'],
    exclusions: ['animal-only', 'review-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database'>('input');
  const [isProcessing, setIsProcessing] = useState(false);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);

    try {
      setStep(WorkflowStep.QUERY_GEN);
      const query = `(${input.active_ingredients.join(' OR ')}) AND (${input.ae_strings.join(' OR ')})`;
      const { rss_url } = pubmed_build_rss_url(query);
      addLog(`Step 0: 生成查詢式與 RSS URL。`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(rss_url);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];
      addLog(`Step 1: RSS 獲取 ${items.length} 筆候選。`);

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids);

      const filteredRecords: PVRecord[] = rawRecords.map(r => ({
        id: `pmid-${r.pmid}`,
        source: 'pubmed',
        pmid: r.pmid,
        doi: r.doi,
        title: r.title,
        authors: r.authors,
        journal: r.journal,
        year: r.year,
        dp: r.dp,
        edat: r.edat,
        abstract: r.abstract,
        primary_link: r.pubmed_url || r.journal_url || '',
        pubmed_url: r.pubmed_url,
        journal_url: r.journal_url,
        quality_flags: [],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false
      }));
      addLog(`Step 2: PubMed EFetch 完成。`);

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: webItems } = await google_search(query, input.date_window.from, input.date_window.to);
      const webRecords: PVRecord[] = webItems.map((wi, idx) => ({
        id: `web-${idx}`,
        source: 'web',
        title: wi.title,
        primary_link: wi.url,
        quality_flags: ['Web-Source'],
        relevance_score: 0,
        relevance_reason: 'Web search result',
        is_excluded: false,
        abstract: wi.snippet // Web 來源以 snippet 作為摘要
      }));
      addLog(`Step 4: Google 網路補強完成。`);

      const allRecords = [...filteredRecords, ...webRecords];

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(allRecords.map(r => ({ id: r.id, title: r.title, abstract: r.abstract })));

      const scoredRecords = allRecords.map(r => {
        const scoreInfo = scores.find((s: any) => s.id === r.id);
        return {
          ...r,
          relevance_score: scoreInfo?.score || 0,
          relevance_reason: scoreInfo?.reason || '無評分理由'
        };
      });
      addLog(`Step 5: AI 相關性評分完成。`);

      setStep(WorkflowStep.SUMMARIZATION);
      const toSummarize = scoredRecords.filter(r => r.relevance_score > 30);
      const summaries = await gemini.generateSummaries(toSummarize.map(r => ({ id: r.id, title: r.title, abstract: r.abstract || r.title })));

      const finalizedRecords = scoredRecords.map(r => {
        const summaryInfo = summaries.find((s: any) => s.id === r.id);
        let summary_zh = '無摘要';

        if (r.relevance_score <= 30) {
          summary_zh = '⚠️ 相關性較低 (≤30)，系統跳過摘要生成。';
        } else if (summaryInfo) {
          summary_zh = summaryInfo.summary_zh;
        } else {
          summary_zh = '摘要生成失敗或資料不足。';
        }

        return {
          ...r,
          summary_zh
        };
      });
      addLog(`Step 6: 繁體中文摘要生成完成。`);

      setRecords(finalizedRecords);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (error) {
      console.error(error);
      addLog(`錯誤: ${error instanceof Error ? error.message : '未知錯誤'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleExclude = async (id: string) => {
    const reason = window.prompt("請輸入刪除理由：", "非相關藥物不良反應");
    if (reason) {
      await db_mark_excluded([id], reason);
      setRecords(prev => prev.map(r => r.id === id ? { ...r, is_excluded: true, exclusion_reason: reason } : r));
    }
  };

  const extractDetailedPV = async (record: PVRecord) => {
    addLog(`開始抽取結構化資料: ${record.title}`);
    const pvData = await gemini.extractPVData(record);
    const cioms = await gemini.generateCIOMS(record, pvData);

    setRecords(prev => prev.map(r => r.id === record.id ? { 
      ...r, 
      pv_data: pvData, 
      cimos_draft: cioms 
    } : r));
    addLog(`抽取完成 ${record.id}`);
  };

  const exportDB = async () => {
    const validRecords = records.filter(r => !r.is_excluded);
    const result = await db_upsert(validRecords);
    const csv = await export_csv_ingredient_view({});
    addLog(`資料庫已更新: 匯入 ${result.inserted} 筆。`);
    alert(`成功匯入 ${result.inserted} 筆資料。`);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-indigo-900 text-white p-4 shadow-lg flex justify-between items-center">
        <div className="flex items-center gap-3">
          <ShieldCheckIcon className="w-8 h-8 text-indigo-300" />
          <h1 className="text-xl font-bold tracking-tight">PV-Link <span className="text-sm font-normal text-indigo-200">藥品安全監測代理系統</span></h1>
        </div>
        <div className="flex items-center gap-4 text-sm">
          <span className="bg-indigo-800 px-3 py-1 rounded-full text-indigo-100 flex items-center gap-2">
            <GlobeAltIcon className="w-4 h-4" /> 監控狀態: {isProcessing ? '搜尋中...' : '閒置'}
          </span>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-64 bg-gray-100 border-r border-gray-200 flex flex-col">
          <nav className="p-4 space-y-2">
            <button 
              onClick={() => setActiveTab('input')}
              className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${activeTab === 'input' ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600 hover:bg-gray-200'}`}
            >
              <MagnifyingGlassIcon className="w-5 h-5" /> 監測設定
            </button>
            <button 
              onClick={() => setActiveTab('review')}
              className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${activeTab === 'review' ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600 hover:bg-gray-200'}`}
            >
              <ClipboardDocumentCheckIcon className="w-5 h-5" /> 待確認區 ({records.filter(r => !r.is_excluded).length})
            </button>
            <button 
              onClick={() => setActiveTab('database')}
              className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${activeTab === 'database' ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600 hover:bg-gray-200'}`}
            >
              <ArrowPathIcon className="w-5 h-5" /> 執行日誌
            </button>
          </nav>
          <div className="mt-auto p-4 border-t border-gray-200 bg-gray-50">
            <button 
              onClick={runWorkflow}
              disabled={isProcessing}
              className="w-full bg-indigo-600 text-white py-2 rounded-lg font-semibold hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {isProcessing ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : <MagnifyingGlassIcon className="w-5 h-5" />}
              開始監測
            </button>
          </div>
        </aside>

        <section className="flex-1 overflow-y-auto bg-white p-6">
          {activeTab === 'input' && (
            <div className="max-w-3xl mx-auto space-y-6">
              <h2 className="text-2xl font-bold text-gray-800 border-b pb-2">監測參數設定</h2>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">公司產品名稱</label>
                  <input type="text" value={input.company_product_names.join(', ')} onChange={(e) => setInput({...input, company_product_names: e.target.value.split(',').map(s => s.trim())})} className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">主成分 (Active Ingredients)</label>
                  <input type="text" value={input.active_ingredients.join(', ')} onChange={(e) => setInput({...input, active_ingredients: e.target.value.split(',').map(s => s.trim())})} className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">日期區間</label>
                  <div className="flex items-center gap-2">
                    <input type="date" value={input.date_window.from} onChange={(e) => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="border rounded-lg p-2 w-full" />
                    <span>至</span>
                    <input type="date" value={input.date_window.to} onChange={(e) => setInput({...input, date_window: {...input.date_window, to: e.target.value}})} className="border rounded-lg p-2 w-full" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">日期邏輯</label>
                  <select value={input.date_logic} onChange={(e) => setInput({...input, date_logic: e.target.value as any})} className="w-full border rounded-lg p-2">
                    <option value="dp">Date of Publication (dp)</option>
                    <option value="edat">Entrez Date (edat)</option>
                    <option value="both">Both</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-gray-700">AE 關鍵字組合</label>
                <textarea rows={3} value={input.ae_strings.join(', ')} onChange={(e) => setInput({...input, ae_strings: e.target.value.split(',').map(s => s.trim())})} className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
              </div>
              <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 flex gap-3">
                <ExclamationCircleIcon className="w-6 h-6 text-amber-600 flex-shrink-0" />
                <p className="text-sm text-amber-800">
                  注意：系統僅會對「相關性評分 > 30」的文獻進行 AI 摘要與結構化抽取，以確保準確性並聚焦重要信號。
                </p>
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="space-y-6">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">待確認文獻清單</h2>
                <button onClick={exportDB} className="bg-green-600 text-white px-4 py-2 rounded-lg font-semibold hover:bg-green-700 flex items-center gap-2">
                  <DocumentArrowDownIcon className="w-5 h-5" /> 匯出至主資料庫
