                        </div>
                        <div className="flex gap-2">
                          <button disabled={record.is_excluded} onClick={() => handleExclude(record.id)} className="p-2 text-gray-400 hover:text-red-600 rounded-full hover:bg-red-50"><TrashIcon className="w-5 h-5" /></button>
                          <button disabled={record.is_excluded || !!record.pv_data} onClick={() => extractDetailedPV(record)} className="p-2 text-gray-400 hover:text-indigo-600 rounded-full hover:bg-indigo-50"><CheckCircleIcon className="w-5 h-5" /></button>
                        </div>
                      </div>

                      {!record.is_excluded && (
                        <div className="mt-4 space-y-4">
                          {/* 原文摘要顯示 (處理無內容情況) */}
                          <div className="bg-gray-50 p-3 rounded-lg border border-gray-100">
                            <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                              <InformationCircleIcon className="w-3 h-3" /> 原文摘要 / Snippet
                            </h4>
                            <p className={`text-sm leading-relaxed ${!record.abstract ? 'text-gray-400 italic' : 'text-gray-700'}`}>
                              {record.abstract || "⚠️ 來源端未偵測到摘要 (PubMed Metadata Missing)"}
                            </p>
                          </div>

                          {/* AI 繁中摘要 */}
                          <div className="bg-indigo-50/50 p-3 rounded-lg border border-indigo-100">
                            <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                              <ArrowPathIcon className="w-3 h-3" /> AI 繁體中文摘要
                            </h4>
                            <p className="text-sm text-gray-800 font-medium">
                              {record.summary_zh}
                            </p>
                          </div>

                          <div className="bg-gray-50 p-3 rounded-lg border border-gray-100">
                            <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">評分理由</h4>
                            <p className="text-sm text-gray-600 italic">"{record.relevance_reason}"</p>
                          </div>
                        </div>
                      )}

                      {record.pv_data && (
                        <div className="mt-4 border-t pt-4">
                          <h4 className="text-sm font-bold text-indigo-700 mb-2 flex items-center gap-2"><ClipboardDocumentCheckIcon className="w-4 h-4" /> 結構化 PV 數據</h4>
                          <div className="grid grid-cols-4 gap-2 text-xs">
                            <div className="bg-indigo-50 p-2 rounded"><span className="block text-gray-500">MedDRA PT</span><span className="font-bold">{record.pv_data.meddra_pt_candidate}</span></div>
                            <div className="bg-indigo-50 p-2 rounded"><span className="block text-gray-500">嚴重性</span><span className="font-bold">{record.pv_data.seriousness}</span></div>
                            <div className="bg-indigo-50 p-2 rounded"><span className="block text-gray-500">途徑</span><span className="font-bold">{record.pv_data.dosage_route}</span></div>
                            <div className="bg-indigo-50 p-2 rounded"><span className="block text-gray-500">因果</span><span className="font-bold">{record.pv_data.causality}</span></div>
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'database' && (
            <div className="space-y-4">
              <h2 className="text-2xl font-bold text-gray-800">執行日誌</h2>
              <div className="bg-gray-900 text-green-400 font-mono text-xs p-4 rounded-lg h-[600px] overflow-y-auto">
                {logs.map((log, i) => <div key={i} className="mb-1">{log}</div>)}
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

