/**
 * 模擬 PV 專用工具集
 * 增加動態反應邏輯，確保搜尋結果與使用者輸入的成分/產品相關
 */

export const pubmed_build_rss_url = (query: string, limit: number = 100) => {
  const encodedQuery = encodeURIComponent(query);
  return { 
    search_run_id: `SR-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
    rss_url: `https://pubmed.ncbi.nlm.nih.gov/rss/search/1${encodedQuery}/?limit=${limit}`,
    pubmed_query: query
  };
};

export const pubmed_fetch_rss = async (rss_url: string, query: string) => {
  // 提取關鍵字以生成模擬資料
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Unknown'];
  const ingredient = keywords[0];

  await new Promise(r => setTimeout(r, 800));
  return {
    items: [
      { 
        title: `Acute respiratory distress associated with ${ingredient} therapy: A case report`, 
        link: "https://pubmed.ncbi.nlm.nih.gov/38812345/", 
        pubDate: "2024-07-10", 
        guid: "38812345", 
        snippet: `A 62-year-old patient developed sudden onset ARDS after 2 weeks of ${ingredient}...` 
      },
      { 
        title: `Long-term safety surveillance of ${ingredient} in elderly populations`, 
        link: "https://pubmed.ncbi.nlm.nih.gov/38812346/", 
        pubDate: "2024-08-15", 
        guid: "38812346", 
        snippet: `Retrospective analysis of ${ingredient} related adverse reactions...` 
      }
    ]
  };
};

export const pubmed_efetch = async (pmids: string[]) => {
  await new Promise(r => setTimeout(r, 600));
  return {
    records: pmids.map(id => ({
      pmid: id,
      doi: `10.1093/pv/article-${id}`,
      title: id === "38812345" ? "Acute respiratory distress associated with therapy: A case report" : "Safety Study",
      authors: ["Chen L", "Watanabe T"],
      journal: "International Journal of Pharmacovigilance",
      year: "2024",
      dp: "2024-07-01", // 提供明確日期以供篩選
      edat: "2024-07-02",
      abstract: "This clinical observation reports a serious adverse event. The patient presented with classic symptoms of toxicity. Causality was assessed as 'Probable' using the Naranjo scale. This case adds to the growing evidence of potential risks associated with the drug class.",
      pubmed_url: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
      journal_url: `https://publisher.com/fulltext/${id}`
    }))
  };
};

export const google_search = async (query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Unknown'];
  const ingredient = keywords[0];

  return {
    items: [
      { 
        title: `Official Safety Alert: Potential risk of skin reactions with ${ingredient}`, 
        url: "https://www.pmda.go.jp/safety/info-services/0001.html", 
        snippet: "Regulatory update regarding post-marketing surveillance data...", 
        displayLink: "pmda.go.jp", 
        date: "2024-09-01" 
      }
    ]
  };
};

