  return { ok: true, inserted: records_json.length, updated: 0, errors: [] };
};

export const db_mark_excluded = async (record_ids: string[], reason: string) => {
  return { ok: true };
};

export const export_csv_ingredient_view = async (filters: any) => {
  return { csv_path_or_data: "CSV DATA" };
};

