import React, { useState, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  ExclamationCircleIcon,
  LinkIcon,
  FingerPrintIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['Drug-A'],
    active_ingredients: ['Active-B'],
    date_window: { from: '2024-01-01', to: '2024-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'unverified' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setUnverifiedQueue([]);

    try {
      // Step 0: Query & RSS 生成 (Auditable Search Log)
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`Step 0: 啟動稽核 ID ${searchMetadata.search_run_id}. 查詢式: ${fullQuery}`);

      // Step 1: RSS 拉取
      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];
      addLog(`Step 1: RSS 發現 ${items.length} 筆可能 PMIDs.`);

      // Step 2 & 3: EFetch + 嚴格時間窗 + 去重 (Deduplication)
      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids);

      const masterList: PVRecord[] = [];
      const unverifiable: PVRecord[] = [];

      rawRecords.forEach(r => {
        // 嚴格時間窗篩選
        const pubDate = new Date(r.dp || '');
        const fromDate = new Date(input.date_window.from);
        const toDate = new Date(input.date_window.to);

        const qFlags: string[] = [];
        if (!r.dp && !r.edat) qFlags.push('MISSING_DATES');
        if (!r.doi && !r.pmid) qFlags.push('UNVERIFIABLE');

        const record: PVRecord = {
          id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
          source: 'pubmed',
          pmid: r.pmid,
          doi: r.doi,
          title: r.title,
          authors: r.authors,
          journal: r.journal,
          year: r.year,
          dp: r.dp,
          abstract: r.abstract,
          primary_link: r.pubmed_url || r.journal_url || '',
          quality_flags: qFlags,
          relevance_score: 0,
          relevance_reason: '',
          is_excluded: false
        };

        // 判定進入主庫或待確認區
        if (qFlags.length > 0 || pubDate < fromDate || pubDate > toDate) {
          if (pubDate < fromDate || pubDate > toDate) record.exclusion_reason = "OUT_OF_WINDOW";
          unverifiable.push(record);
        } else {
          masterList.push(record);
        }
      });
      addLog(`Step 2/3: 完成篩選。主庫 ${masterList.length} 筆，待驗證/過期 ${unverifiable.length} 筆。`);

      // Step 4: Google 補強 (Trusted Domains only)
      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi, idx) => {
        const isTrusted = gi.displayLink.includes('.gov') || gi.displayLink.includes('.org') || gi.displayLink.includes('.edu');
        const webRec: PVRecord = {
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: isTrusted ? [] : ['UNTRUSTED_DOMAIN'],
          relevance_score: 0,
          relevance_reason: 'Web search reinforcement',
          is_excluded: false,
          abstract: gi.snippet
        };
        if (isTrusted) masterList.push(webRec);
        else unverifiable.push(webRec);
      });

      // Step 5: PV Relevance Scoring (ICH E2B Focus)
      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));
      const scoredMaster = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || 'No data' };
      });

      // Step 6: Summarization
      setStep(WorkflowStep.SUMMARIZATION);
      const toSummary = scoredMaster.filter(m => m.relevance_score > 30);
      const summaries = await gemini.generateSummaries(toSummary.map(m => ({ id: m.id, abstract: m.abstract || m.title })));
      const finalMaster = scoredMaster.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || (m.relevance_score <= 30 ? '相關性過低，跳過摘要' : '摘要生成失敗') };
      });

      setRecords(finalMaster);
      setUnverifiedQueue(unverifiable);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`工作流完成。請進行人工核閱。`);
    } catch (e) {
      addLog(`CRITICAL ERROR: ${e instanceof Error ? e.message : 'System Failure'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDetailedExtraction = async (record: PVRecord) => {
    addLog(`Step 7: 正在針對 ${record.id} 進行 MedDRA 對齊與結構化抽取...`);
    const data = await gemini.extractPVData(record);
    const cioms = await gemini.generateCIOMS(record, data);
    setRecords(prev => prev.map(r => r.id === record.id ? { ...r, pv_data: data, cimos_draft: cioms } : r));
    addLog(`完成 ${record.id} 抽取。完整度: ${data.completeness}`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      {/* Top Audit Header */}
      <div className="bg-slate-900 text-slate-400 px-4 py-1 text-[10px] flex justify-between items-center border-b border-slate-700 font-mono">
        <div className="flex items-center gap-4">
          <span>SYSTEM_VERSION: v2.1-PRO</span>
          <span>SEARCH_RUN_ID: {searchRunInfo?.id || 'N/A'}</span>
        </div>
        <div>
          {now().iso_datetime}
        </div>
      </div>

      <header className="bg-indigo-900 text-white p-4 shadow-md flex justify-between items-center">
        <div className="flex items-center gap-3">
          <ShieldCheckIcon className="w-8 h-8 text-indigo-400" />
          <div>
            <h1 className="text-xl font-bold tracking-tight">PV-Link Auditor</h1>
            <p className="text-[10px] text-indigo-300 uppercase tracking-widest">Pharmacovigilance Intelligence System</p>
          </div>
        </div>
        <div className="flex gap-2">
          {isProcessing && (
            <div className="flex items-center gap-2 bg-indigo-800 px-3 py-1 rounded-full text-xs animate-pulse">
              <ArrowPathIcon className="w-3 h-3 animate-spin" /> 正在執行 Step {step}...
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Navigation Sidebar */}
        <nav className="w-64 bg-white border-r border-gray-200 p-4 space-y-1">
          <button onClick={() => setActiveTab('input')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'input' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <MagnifyingGlassIcon className="w-5 h-5" /> 監測參數設定
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'review' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 主資料庫核閱 ({records.length})
          </button>
          <button onClick={() => setActiveTab('unverified')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'unverified' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <ExclamationTriangleIcon className="w-5 h-5 text-amber-500" /> 待確認/排除區 ({unverifiedQueue.length})
          </button>
          <button onClick={() => setActiveTab('logs')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'logs' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <FingerPrintIcon className="w-5 h-5" /> 稽核日誌
          </button>

          <div className="pt-4 border-t mt-4">
            <button 
              onClick={runWorkflow}
              disabled={isProcessing}
              className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-indigo-200 shadow-lg disabled:opacity-50 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <MagnifyingGlassIcon className="w-5 h-5" />
              啟動自動監測
            </button>
          </div>
        </nav>

        {/* Content Section */}
        <section className="flex-1 overflow-y-auto p-6">
          {activeTab === 'input' && (
            <div className="max-w-2xl mx-auto space-y-8">
              <div className="bg-white border rounded-2xl p-6 shadow-sm space-y-6">
                <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 border-b pb-3">
                  <ShieldCheckIcon className="w-5 h-5 text-indigo-600" /> 核心監視對象
                </h2>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">產品名稱 (Product Names)</label>
                    <input type="text" value={input.company_product_names.join(', ')} onChange={e => setInput({...input, company_product_names: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">主成分 (Active Ingredients)</label>
                    <input type="text" value={input.active_ingredients.join(', ')} onChange={e => setInput({...input, active_ingredients: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">AE 關鍵字邏輯</label>
                  <textarea rows={2} value={input.ae_strings.join(', ')} onChange={e => setInput({...input, ae_strings: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 flex gap-3 italic text-xs text-blue-700">
                <InformationCircleIcon className="w-5 h-5 flex-shrink-0" />
                系統將嚴格執行 Step 2 篩選：若無 PMID/DOI 或發布日期不在區間內，資料將被隔離至「待確認區」。
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center border-b pb-4">
                <h2 className="text-xl font-bold text-slate-800">主資料庫核閱 (合格文獻)</h2>
                <div className="flex gap-2">
                  <button onClick={() => db_upsert(records)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-indigo-700">
                    <DocumentArrowDownIcon className="w-4 h-4" /> 匯出 CIOMS / CSV
                  </button>
                </div>
              </div>

              {records.length === 0 ? (
                <div className="py-20 text-center text-slate-400 italic">尚未發現合格資料。請檢查監測參數或日期窗口。</div>
              ) : (
                <div className="space-y-4">
                  {records.map(r => (
                    <div key={r.id} className="bg-white border rounded-xl overflow-hidden shadow-sm hover:border-indigo-300 transition-all">
                      <div className="p-4 border-b bg-slate-50 flex justify-between items-start">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="bg-indigo-100 text-indigo-700 text-[10px] px-2 py-0.5 rounded-full font-bold uppercase">{r.source}</span>
                            <span className="text-[10px] text-slate-500 font-mono">{r.pmid || r.doi}</span>
                            <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${r.relevance_score > 70 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                              RELEVANCE: {r.relevance_score}%
                            </span>
                          </div>
                          <h3 className="font-bold text-slate-800 leading-tight underline decoration-indigo-200 hover:decoration-indigo-500 cursor-pointer">
                            <a href={r.primary_link} target="_blank">{r.title}</a>
                          </h3>
                        </div>
                        <div className="flex gap-1">
                          <button onClick={() => handleDetailedExtraction(r)} disabled={!!r.pv_data} className="p-2 text-indigo-600 hover:bg-indigo-100 rounded-lg title='抽取結構化資料'">
                            <CheckCircleIcon className="w-5 h-5" />
                          </button>
                          <button className="p-2 text-red-400 hover:bg-red-50 rounded-lg">
                            <TrashIcon className="w-5 h-5" />
                          </button>
                        </div>
                      </div>

                      <div className="p-4 grid grid-cols-3 gap-6">
                        <div className="col-span-2 space-y-3">
                          <div>
                            <label className="text-[10px] font-bold text-slate-400 uppercase">PV 繁中摘要</label>
                            <p className="text-sm text-slate-700 leading-relaxed font-medium">{r.summary_zh}</p>
                          </div>
                          <div className="bg-slate-50 p-2 rounded text-[10px] text-slate-500 italic">
                            REASON: {r.relevance_reason}
                          </div>
                        </div>

                        {r.pv_data && (
                          <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100 space-y-2">
                            <h4 className="text-[10px] font-bold text-indigo-700 uppercase flex items-center gap-1">
                              <ShieldCheckIcon className="w-3 h-3" /> E2B(R3) 抽取結果
                            </h4>
                            <div className="text-[10px] space-y-1">
                              <div className="flex justify-between"><span>MedDRA PT:</span><span className="font-bold">{r.pv_data.meddra_pt_candidate}</span></div>
                              <div className="flex justify-between"><span>Seriousness:</span><span className="font-bold">{r.pv_data.seriousness}</span></div>
                              <div className="flex justify-between"><span>Causality:</span><span className="font-bold text-indigo-600">{r.pv_data.causality}</span></div>
                              <div className="flex justify-between"><span>Status:</span><span className="text-green-600 font-bold">{r.pv_data.completeness}</span></div>
                            </div>
                            <button className="w-full mt-2 bg-indigo-200 text-indigo-800 text-[10px] py-1 rounded font-bold hover:bg-indigo-300">產出 CIOMS 草稿</button>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'unverified' && (
            <div className="space-y-4">
               <div className="flex justify-between items-center border-b pb-4">
                <h2 className="text-xl font-bold text-amber-800 flex items-center gap-2">
                  <ExclamationTriangleIcon className="w-6 h-6" /> 待確認 / 排除區
                </h2>
              </div>
              <p className="text-xs text-slate-500 italic">以下資料因缺少關鍵驗證資訊（PMID/DOI/日期）或超出時間窗，系統已自動隔離，不計入正式報表。</p>

              <div className="space-y-2">
                {unverifiedQueue.map(u => (
                  <div key={u.id} className="bg-white border-l-4 border-amber-400 p-3 shadow-sm flex justify-between items-center opacity-75 grayscale hover:grayscale-0 transition-all">
                    <div className="flex-1">
                      <div className="flex gap-2 mb-1">
                        {u.quality_flags.map(f => (
                          <span key={f} className="bg-amber-100 text-amber-700 text-[8px] px-1 rounded font-bold">{f}</span>
                        ))}
                      </div>
                      <h4 className="text-sm font-bold text-slate-700">{u.title}</h4>
                      <div className="text-[10px] text-slate-400 flex gap-4">
                         <span>來源: {u.source}</span>
                         <span>日期: {u.dp || 'Missing'}</span>
                         {u.exclusion_reason && <span className="text-red-500 font-bold">原因: {u.exclusion_reason}</span>}
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button className="text-xs text-indigo-600 font-bold hover:underline">手動核准</button>
                       <button className="text-xs text-red-600 font-bold hover:underline">永久刪除</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="space-y-4 h-full flex flex-col">
              <h2 className="text-xl font-bold text-slate-800">系統執行日誌 (Audit Trail)</h2>
              <div className="flex-1 bg-slate-900 rounded-xl p-4 font-mono text-xs text-green-400 overflow-y-auto shadow-inner">
                {logs.map((l, i) => <div key={i} className="mb-1 opacity-80 hover:opacity-100">{l}</div>)}
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="bg-slate-50 border-t p-2 text-[9px] text-slate-400 flex justify-between">
         <span>&copy; 2024 PV-Link Intelligence Auditor. Compliance with ICH E2B(R3) & TFDA Guidelines.</span>
         <span className="flex gap-4">
            <span className="flex items-center gap-1"><LinkIcon className="w-2 h-2"/> PubMed API Connected</span>
            <span className="flex items-center gap-1"><LinkIcon className="w-2 h-2"/> MedDRA DB Linked</span>
         </span>
      </footer>
    </div>
  );
};

export default App;

export interface PVInput {
  company_product_names: string[];
  active_ingredients: string[];
  date_window: { from: string; to: string };
  date_logic: 'dp' | 'edat' | 'both';
  ae_strings: string[];
  optional_ae_focus_terms: string[];
  exclusions: string[];
  db_mode: 'insert-only' | 'upsert';
}

export interface PVRecord {
  id: string;
  source: 'pubmed' | 'web';
  pmid?: string;
  doi?: string;
  title: string;
  authors?: string[];
  journal?: string;
  year?: string;
  dp?: string;
  edat?: string;
  abstract?: string;
  primary_link: string;
  pubmed_url?: string;
  journal_url?: string;
  quality_flags: string[]; // ['MISSING_DATES', 'UNVERIFIABLE', 'UNTRUSTED_DOMAIN']
  relevance_score: number;
  relevance_reason: string;
  summary_zh?: string;
  is_excluded: boolean;
  exclusion_reason?: string; // e.g. 'OUT_OF_WINDOW', 'NOT_AE'
  pv_data?: PVStructuredData;
  cimos_draft?: any;
}

export interface PVStructuredData {
  product: string;
  ingredient: string;
  ae_verbatim: string;
  meddra_pt_candidate: string;
  meddra_confidence: number;
  seriousness: string;
  population: string;
  dosage_route: string;
  tto: string;
  outcome: string;
  causality: string;
  completeness: 'Complete' | 'Partial' | 'Missing';
}

export enum WorkflowStep {
  IDLE = "閒置",
  QUERY_GEN = "查詢式生成",
  RSS_FETCH = "RSS 獲取",
  EFETCH_FILTER = "嚴格篩選與去重",
  WEB_SEARCH = "網路來源補強",
  RELEVANCE_SCORING = "PV 相關性評分",
  SUMMARIZATION = "繁中摘要生成",
  PV_EXTRACTION = "結構化抽取",
  DB_EXPORT = "資料庫匯入"
}

import React, { useState, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  ExclamationCircleIcon,
  LinkIcon,
  FingerPrintIcon,
  InformationCircleIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['Drug-A'],
    active_ingredients: ['Active-B'],
    date_window: { from: '2024-01-01', to: '2024-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'unverified' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setUnverifiedQueue([]);

    try {
      // Step 0: Query & RSS 生成 (Auditable Search Log)
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`Step 0: 啟動稽核 ID ${searchMetadata.search_run_id}. 查詢式: ${fullQuery}`);

      // Step 1: RSS 拉取
      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];
      addLog(`Step 1: RSS 發現 ${items.length} 筆可能 PMIDs.`);

      // Step 2 & 3: EFetch + 嚴格時間窗 + 去重 (Deduplication)
      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids);

      const masterList: PVRecord[] = [];
      const unverifiable: PVRecord[] = [];

      rawRecords.forEach(r => {
        // 嚴格時間窗篩選
        const pubDate = new Date(r.dp || '');
        const fromDate = new Date(input.date_window.from);
        const toDate = new Date(input.date_window.to);

        const qFlags: string[] = [];
        if (!r.dp && !r.edat) qFlags.push('MISSING_DATES');
        if (!r.doi && !r.pmid) qFlags.push('UNVERIFIABLE');

        const record: PVRecord = {
          id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
          source: 'pubmed',
          pmid: r.pmid,
          doi: r.doi,
          title: r.title,
          authors: r.authors,
          journal: r.journal,
          year: r.year,
          dp: r.dp,
          abstract: r.abstract,
          primary_link: r.pubmed_url || r.journal_url || '',
          quality_flags: qFlags,
          relevance_score: 0,
          relevance_reason: '',
          is_excluded: false
        };

        // 判定進入主庫或待確認區
        if (qFlags.length > 0 || pubDate < fromDate || pubDate > toDate) {
          if (pubDate < fromDate || pubDate > toDate) record.exclusion_reason = "OUT_OF_WINDOW";
          unverifiable.push(record);
        } else {
          masterList.push(record);
        }
      });
      addLog(`Step 2/3: 完成篩選。主庫 ${masterList.length} 筆，待驗證/過期 ${unverifiable.length} 筆。`);

      // Step 4: Google 補強 (Trusted Domains only)
      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi, idx) => {
        const isTrusted = gi.displayLink.includes('.gov') || gi.displayLink.includes('.org') || gi.displayLink.includes('.edu');
        const webRec: PVRecord = {
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: isTrusted ? [] : ['UNTRUSTED_DOMAIN'],
          relevance_score: 0,
          relevance_reason: 'Web search reinforcement',
          is_excluded: false,
          abstract: gi.snippet
        };
        if (isTrusted) masterList.push(webRec);
        else unverifiable.push(webRec);
      });

      // Step 5: PV Relevance Scoring (ICH E2B Focus)
      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));
      const scoredMaster = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || 'No data' };
      });

      // Step 6: Summarization
      setStep(WorkflowStep.SUMMARIZATION);
      const toSummary = scoredMaster.filter(m => m.relevance_score > 30);
      const summaries = await gemini.generateSummaries(toSummary.map(m => ({ id: m.id, abstract: m.abstract || m.title })));
      const finalMaster = scoredMaster.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || (m.relevance_score <= 30 ? '相關性過低，跳過摘要' : '摘要生成失敗') };
      });

      setRecords(finalMaster);
      setUnverifiedQueue(unverifiable);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`工作流完成。請進行人工核閱。`);
    } catch (e) {
      addLog(`CRITICAL ERROR: ${e instanceof Error ? e.message : 'System Failure'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDetailedExtraction = async (record: PVRecord) => {
    addLog(`Step 7: 正在針對 ${record.id} 進行 MedDRA 對齊與結構化抽取...`);
    const data = await gemini.extractPVData(record);
    const cioms = await gemini.generateCIOMS(record, data);
    setRecords(prev => prev.map(r => r.id === record.id ? { ...r, pv_data: data, cimos_draft: cioms } : r));
    addLog(`完成 ${record.id} 抽取。完整度: ${data.completeness}`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      {/* Top Audit Header */}
      <div className="bg-slate-900 text-slate-400 px-4 py-1 text-[10px] flex justify-between items-center border-b border-slate-700 font-mono">
        <div className="flex items-center gap-4">
          <span>SYSTEM_VERSION: v2.1-PRO</span>
          <span>SEARCH_RUN_ID: {searchRunInfo?.id || 'N/A'}</span>
        </div>
        <div>
          {now().iso_datetime}
        </div>
      </div>

      <header className="bg-indigo-900 text-white p-4 shadow-md flex justify-between items-center">
        <div className="flex items-center gap-3">
          <ShieldCheckIcon className="w-8 h-8 text-indigo-400" />
          <div>
            <h1 className="text-xl font-bold tracking-tight">PV-Link Auditor</h1>
            <p className="text-[10px] text-indigo-300 uppercase tracking-widest">Pharmacovigilance Intelligence System</p>
          </div>
        </div>
        <div className="flex gap-2">
          {isProcessing && (
            <div className="flex items-center gap-2 bg-indigo-800 px-3 py-1 rounded-full text-xs animate-pulse">
              <ArrowPathIcon className="w-3 h-3 animate-spin" /> 正在執行 Step {step}...
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Navigation Sidebar */}
        <nav className="w-64 bg-white border-r border-gray-200 p-4 space-y-1">
          <button onClick={() => setActiveTab('input')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'input' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <MagnifyingGlassIcon className="w-5 h-5" /> 監測參數設定
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'review' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 主資料庫核閱 ({records.length})
          </button>
          <button onClick={() => setActiveTab('unverified')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'unverified' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <ExclamationTriangleIcon className="w-5 h-5 text-amber-500" /> 待確認/排除區 ({unverifiedQueue.length})
          </button>
          <button onClick={() => setActiveTab('logs')} className={`w-full text-left px-4 py-2 rounded-lg text-sm flex items-center gap-3 ${activeTab === 'logs' ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-gray-600 hover:bg-gray-50'}`}>
            <FingerPrintIcon className="w-5 h-5" /> 稽核日誌
          </button>

          <div className="pt-4 border-t mt-4">
            <button 
              onClick={runWorkflow}
              disabled={isProcessing}
              className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-indigo-200 shadow-lg disabled:opacity-50 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <MagnifyingGlassIcon className="w-5 h-5" />
              啟動自動監測
            </button>
          </div>
        </nav>

        {/* Content Section */}
        <section className="flex-1 overflow-y-auto p-6">
          {activeTab === 'input' && (
            <div className="max-w-2xl mx-auto space-y-8">
              <div className="bg-white border rounded-2xl p-6 shadow-sm space-y-6">
                <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 border-b pb-3">
                  <ShieldCheckIcon className="w-5 h-5 text-indigo-600" /> 核心監視對象
                </h2>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">產品名稱 (Product Names)</label>
                    <input type="text" value={input.company_product_names.join(', ')} onChange={e => setInput({...input, company_product_names: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">主成分 (Active Ingredients)</label>
                    <input type="text" value={input.active_ingredients.join(', ')} onChange={e => setInput({...input, active_ingredients: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">AE 關鍵字邏輯</label>
                  <textarea rows={2} value={input.ae_strings.join(', ')} onChange={e => setInput({...input, ae_strings: e.target.value.split(',').map(s=>s.trim())})} className="w-full border-gray-200 border rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 flex gap-3 italic text-xs text-blue-700">
                <InformationCircleIcon className="w-5 h-5 flex-shrink-0" />
                系統將嚴格執行 Step 2 篩選：若無 PMID/DOI 或發布日期不在區間內，資料將被隔離至「待確認區」。
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center border-b pb-4">
                <h2 className="text-xl font-bold text-slate-800">主資料庫核閱 (合格文獻)</h2>
                <div className="flex gap-2">
                  <button onClick={() => db_upsert(records)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-indigo-700">
                    <DocumentArrowDownIcon className="w-4 h-4" /> 匯出 CIOMS / CSV
                  </button>
                </div>
              </div>

              {records.length === 0 ? (
                <div className="py-20 text-center text-slate-400 italic">尚未發現合格資料。請檢查監測參數或日期窗口。</div>
              ) : (
                <div className="space-y-4">
                  {records.map(r => (
                    <div key={r.id} className="bg-white border rounded-xl overflow-hidden shadow-sm hover:border-indigo-300 transition-all">
                      <div className="p-4 border-b bg-slate-50 flex justify-between items-start">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="bg-indigo-100 text-indigo-700 text-[10px] px-2 py-0.5 rounded-full font-bold uppercase">{r.source}</span>
                            <span className="text-[10px] text-slate-500 font-mono">{r.pmid || r.doi}</span>
                            <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${r.relevance_score > 70 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                              RELEVANCE: {r.relevance_score}%
                            </span>
                          </div>
                          <h3 className="font-bold text-slate-800 leading-tight underline decoration-indigo-200 hover:decoration-indigo-500 cursor-pointer">
                            <a href={r.primary_link} target="_blank">{r.title}</a>
                          </h3>
                        </div>
                        <div className="flex gap-1">
                          <button onClick={() => handleDetailedExtraction(r)} disabled={!!r.pv_data} className="p-2 text-indigo-600 hover:bg-indigo-100 rounded-lg title='抽取結構化資料'">
                            <CheckCircleIcon className="w-5 h-5" />
                          </button>
                          <button className="p-2 text-red-400 hover:bg-red-50 rounded-lg">
                            <TrashIcon className="w-5 h-5" />
                          </button>
                        </div>
                      </div>

                      <div className="p-4 grid grid-cols-3 gap-6">
                        <div className="col-span-2 space-y-3">
                          <div>
                            <label className="text-[10px] font-bold text-slate-400 uppercase">PV 繁中摘要</label>
                            <p className="text-sm text-slate-700 leading-relaxed font-medium">{r.summary_zh}</p>
                          </div>
                          <div className="bg-slate-50 p-2 rounded text-[10px] text-slate-500 italic">
                            REASON: {r.relevance_reason}
                          </div>
                        </div>

                        {r.pv_data && (
                          <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100 space-y-2">
                            <h4 className="text-[10px] font-bold text-indigo-700 uppercase flex items-center gap-1">
                              <ShieldCheckIcon className="w-3 h-3" /> E2B(R3) 抽取結果
                            </h4>
                            <div className="text-[10px] space-y-1">
                              <div className="flex justify-between"><span>MedDRA PT:</span><span className="font-bold">{r.pv_data.meddra_pt_candidate}</span></div>
                              <div className="flex justify-between"><span>Seriousness:</span><span className="font-bold">{r.pv_data.seriousness}</span></div>
                              <div className="flex justify-between"><span>Causality:</span><span className="font-bold text-indigo-600">{r.pv_data.causality}</span></div>
                              <div className="flex justify-between"><span>Status:</span><span className="text-green-600 font-bold">{r.pv_data.completeness}</span></div>
                            </div>
                            <button className="w-full mt-2 bg-indigo-200 text-indigo-800 text-[10px] py-1 rounded font-bold hover:bg-indigo-300">產出 CIOMS 草稿</button>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'unverified' && (
            <div className="space-y-4">
               <div className="flex justify-between items-center border-b pb-4">
                <h2 className="text-xl font-bold text-amber-800 flex items-center gap-2">
                  <ExclamationTriangleIcon className="w-6 h-6" /> 待確認 / 排除區
                </h2>
              </div>
              <p className="text-xs text-slate-500 italic">以下資料因缺少關鍵驗證資訊（PMID/DOI/日期）或超出時間窗，系統已自動隔離，不計入正式報表。</p>

              <div className="space-y-2">
                {unverifiedQueue.map(u => (
