const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['主成分B'],
    date_window: { from: '2024-01-01', to: '2024-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'unverified' | 'logs'>('review');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setUnverifiedQueue([]);

    try {
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`[稽核] 建立搜尋任務 ${searchMetadata.search_run_id}`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids, fullQuery);

      const masterList: PVRecord[] = [];
      const unverifiable: PVRecord[] = [];

      rawRecords.forEach(r => {
        const pubDate = new Date(r.dp || '');
        const fromDate = new Date(input.date_window.from);
        const toDate = new Date(input.date_window.to);

        const qFlags: string[] = [];
        if (!r.dp) qFlags.push('MISSING_DATE');
        if (!r.pmid && !r.doi) qFlags.push('NO_IDENTITY');

        const record: PVRecord = {
          id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
          source: 'pubmed',
          pmid: r.pmid,
          doi: r.doi,
          title: r.title,
          authors: r.authors,
          journal: r.journal,
          year: r.year,
          dp: r.dp,
          abstract: r.abstract,
          primary_link: r.pubmed_url || r.journal_url || '',
          quality_flags: qFlags,
          relevance_score: 0,
          relevance_reason: '',
          is_excluded: false
        };

        if (qFlags.length > 0 || pubDate < fromDate || pubDate > toDate) {
          record.exclusion_reason = pubDate < fromDate ? "OUT_OF_WINDOW" : "VERIFICATION_FAILED";
          unverifiable.push(record);
        } else {
          masterList.push(record);
        }
      });

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi, idx) => {
        const webRec: PVRecord = {
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: [],
          relevance_score: 0,
          relevance_reason: 'Regulatory search',
          is_excluded: false,
          abstract: gi.snippet
        };
        masterList.push(webRec);
      });

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));

      setStep(WorkflowStep.SUMMARIZATION);
      const toSummary = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || '' };
      });

      const summaries = await gemini.generateSummaries(toSummary.filter(m => m.relevance_score > 30).map(m => ({ id: m.id, abstract: m.abstract || m.title })));

      const finalRecords = toSummary.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || "未達摘要門檻" };
      });

      setRecords(finalRecords);
      setUnverifiedQueue(unverifiable);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，共發現 ${finalRecords.length} 筆有效文獻。`);
    } catch (e) {
      addLog(`[錯誤] 流程中斷: ${e instanceof Error ? e.message : '未知錯誤'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  return (
    <div className="min-h-screen flex flex-col bg-gray-100 text-slate-900">
      {/* Top Banner */}
      <div className="bg-slate-950 text-slate-500 text-[10px] px-4 py-1 flex justify-between font-mono">
        <span>PV-AUDIT-TRACKER // RUN: {searchRunInfo?.id || 'IDLE'}</span>
        <span className="flex gap-4">
          <span>SOURCE: PUBMED_RSS + GOOGLE_TRUSTED</span>
          <span>STAMP: {now().iso_datetime}</span>
        </span>
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2 rounded-lg text-white">
            <ShieldCheckIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight">PV-Link Auditor</h1>
            <p className="text-xs text-slate-400 font-medium">藥品安全監測與稽核對照系統</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {isProcessing && (
            <div className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-full text-xs text-indigo-600 font-bold animate-pulse">
              <ArrowPathIcon className="w-3 h-3 animate-spin" /> {step}...
            </div>
          )}
          <button 
            onClick={runWorkflow}
            disabled={isProcessing}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-5 py-2 rounded-lg text-sm font-bold shadow-md transition-all active:scale-95 flex items-center gap-2"
          >
            <MagnifyingGlassIcon className="w-4 h-4" />
            啟動監測流程
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Left Nav */}
        <aside className="w-64 bg-white border-r border-slate-200 flex flex-col">
          <div className="p-4 space-y-1">
            <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'input' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <QueueListIcon className="w-5 h-5" /> 監控配置
            </button>
            <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'review' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <ClipboardDocumentCheckIcon className="w-5 h-5" /> 文獻核閱 ({records.length})
            </button>
            <button onClick={() => setActiveTab('unverified')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'unverified' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
