        {/* Content Area */}
        <section className="flex-1 overflow-y-auto flex bg-slate-50">
          {activeTab === 'input' && (
            <div className="w-full p-8 max-w-2xl mx-auto space-y-6">
              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-xl space-y-8">
