                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-xs font-black text-slate-400 uppercase mb-1 block">搜尋起始日期</label>
                      <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-2 font-bold outline-none" />
