                    <div className="grid grid-cols-1 gap-6">
                      {/* Left: Raw Source Data */}
                      <div className="bg-slate-50 border border-slate-200 rounded-3xl p-6 relative overflow-hidden">
                        <div className="absolute top-0 right-0 bg-slate-200 px-4 py-1 rounded-bl-2xl text-[10px] font-black text-slate-500 uppercase tracking-widest">
