                    </div>

                    <div className="pt-6 border-t border-slate-100 flex gap-4">
                       <button className="flex-1 bg-green-600 text-white py-3 rounded-2xl font-black hover:bg-green-700 transition-all flex items-center justify-center gap-2">
                         <CheckCircleIcon className="w-5 h-5" /> 確認無誤・匯入 CIOMS
                       </button>
                       <button className="px-6 bg-slate-100 text-slate-600 py-3 rounded-2xl font-black hover:bg-red-50 hover:text-red-600 transition-all">
                         排除
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-slate-300 space-y-4">
                    <DocumentMagnifyingGlassIcon className="w-16 h-16 opacity-20" />
                    <p className="font-bold">請從左側選擇文獻進行驗證對照</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'unverified' && (
            <div className="w-full p-8 max-w-4xl mx-auto space-y-4">
               <h2 className="text-2xl font-black text-amber-800 tracking-tight flex items-center gap-3">
                  <ExclamationTriangleIcon className="w-8 h-8" /> 被系統強制隔離的資料
               </h2>
               <p className="text-sm text-slate-500 font-medium bg-white p-4 rounded-2xl border border-slate-200">
                  以下文獻因<strong>「資料對不起來」</strong>（缺少 PMID、DOI 或日期超出範圍）被自動攔截。這確保了主資料庫中每一筆紀錄都是百分之百可回查驗證的。
               </p>

               <div className="grid grid-cols-1 gap-3">
                  {unverifiedQueue.map(u => (
                    <div key={u.id} className="bg-white border-2 border-amber-100 p-5 rounded-3xl flex justify-between items-center group hover:border-amber-400 transition-all">
                      <div className="space-y-1">
