                           {u.quality_flags.map(f => <span key={f} className="bg-amber-100 text-amber-700 text-[9px] px-2 py-0.5 rounded font-black uppercase">{f}</span>)}
                        </div>
                        <h4 className="font-bold text-slate-700">{u.title}</h4>
                        <div className="text-[10px] text-slate-400 flex gap-4 font-bold">
                           <span>來源: {u.source}</span>
                           <span>檢索日期: {u.dp || 'N/A'}</span>
                           <span className="text-red-500">隔離理由: {u.exclusion_reason}</span>
                        </div>
                      </div>
                      <div className="flex gap-3">
                        <button className="text-xs font-black text-indigo-600 hover:underline">手動核准</button>
                        <button className="text-xs font-black text-slate-300 hover:text-red-600">放棄</button>
