};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  ExclamationCircleIcon,
  LinkIcon,
  FingerPrintIcon,
  InformationCircleIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['主成分B'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'unverified' | 'logs'>('review');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setUnverifiedQueue([]);

    try {
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`[稽核] 建立搜尋任務 ${searchMetadata.search_run_id}`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids, fullQuery);

      const masterList: PVRecord[] = [];
      const unverifiable: PVRecord[] = [];

      rawRecords.forEach(r => {
        const pubDate = new Date(r.dp || '');
        const fromDate = new Date(input.date_window.from);
        const toDate = new Date(input.date_window.to);

        const qFlags: string[] = [];
        if (!r.dp) qFlags.push('MISSING_DATE');
        if (!r.pmid && !r.doi) qFlags.push('NO_IDENTITY');

        const record: PVRecord = {
          id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
          source: 'pubmed',
          pmid: r.pmid,
          doi: r.doi,
          title: r.title,
          authors: r.authors,
          journal: r.journal,
          year: r.year,
          dp: r.dp,
          abstract: r.abstract,
          primary_link: r.pubmed_url || r.journal_url || '',
          quality_flags: qFlags,
          relevance_score: 0,
          relevance_reason: '',
          is_excluded: false
        };

        if (qFlags.length > 0 || pubDate < fromDate || pubDate > toDate) {
          record.exclusion_reason = pubDate < fromDate ? "OUT_OF_WINDOW" : "VERIFICATION_FAILED";
          unverifiable.push(record);
        } else {
          masterList.push(record);
        }
      });

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi, idx) => {
        const webRec: PVRecord = {
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: [],
          relevance_score: 0,
          relevance_reason: 'Regulatory search',
          is_excluded: false,
          abstract: gi.snippet
        };
        masterList.push(webRec);
      });

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));

      setStep(WorkflowStep.SUMMARIZATION);
      const toSummary = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || '' };
      });

      const summaries = await gemini.generateSummaries(toSummary.filter(m => m.relevance_score > 30).map(m => ({ id: m.id, abstract: m.abstract || m.title })));

      const finalRecords = toSummary.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || "未達摘要門檻" };
      });

      setRecords(finalRecords);
      setUnverifiedQueue(unverifiable);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，共發現 ${finalRecords.length} 筆有效文獻。`);
    } catch (e) {
      addLog(`[錯誤] 流程中斷: ${e instanceof Error ? e.message : '未知錯誤'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  return (
    <div className="min-h-screen flex flex-col bg-gray-100 text-slate-900">
      {/* Top Banner */}
      <div className="bg-slate-950 text-slate-500 text-[10px] px-4 py-1 flex justify-between font-mono">
        <span>PV-AUDIT-TRACKER // RUN: {searchRunInfo?.id || 'IDLE'}</span>
        <span className="flex gap-4">
          <span>SOURCE: PUBMED_RSS + GOOGLE_TRUSTED</span>
          <span>STAMP: {now().iso_datetime}</span>
        </span>
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2 rounded-lg text-white">
            <ShieldCheckIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight">PV-Link Auditor</h1>
            <p className="text-xs text-slate-400 font-medium">藥品安全監測與稽核對照系統</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {isProcessing && (
            <div className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-full text-xs text-indigo-600 font-bold animate-pulse">
              <ArrowPathIcon className="w-3 h-3 animate-spin" /> {step}...
            </div>
          )}
          <button 
            onClick={runWorkflow}
            disabled={isProcessing}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-5 py-2 rounded-lg text-sm font-bold shadow-md transition-all active:scale-95 flex items-center gap-2"
          >
            <MagnifyingGlassIcon className="w-4 h-4" />
            啟動監測流程
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Left Nav */}
        <aside className="w-64 bg-white border-r border-slate-200 flex flex-col">
          <div className="p-4 space-y-1">
            <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'input' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <QueueListIcon className="w-5 h-5" /> 監控配置
            </button>
            <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'review' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <ClipboardDocumentCheckIcon className="w-5 h-5" /> 文獻核閱 ({records.length})
            </button>
            <button onClick={() => setActiveTab('unverified')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'unverified' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <ExclamationTriangleIcon className="w-5 h-5 text-amber-500" /> 待確認區 ({unverifiedQueue.length})
            </button>
            <button onClick={() => setActiveTab('logs')} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-semibold transition-all ${activeTab === 'logs' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FingerPrintIcon className="w-5 h-5" /> 稽核日誌
            </button>
          </div>

          <div className="mt-auto p-4 border-t bg-slate-50/50">
            <div className="text-[10px] text-slate-400 font-bold uppercase mb-2">系統完整度</div>
            <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
              <div className="bg-green-500 h-full w-[85%]"></div>
            </div>
            <p className="text-[10px] text-slate-500 mt-2 italic">符合 ICH E2B(R3) 與 MedDRA 標準</p>
          </div>
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-y-auto flex bg-slate-50">
          {activeTab === 'input' && (
            <div className="w-full p-8 max-w-2xl mx-auto space-y-6">
              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-xl space-y-8">
                <h2 className="text-2xl font-black text-slate-800 tracking-tight">監測目標設定</h2>

                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-black text-slate-400 uppercase mb-1 block">主成分 (Active Ingredient)</label>
                    <input type="text" value={input.active_ingredients[0]} onChange={e => setInput({...input, active_ingredients: [e.target.value]})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-3 text-lg font-bold focus:border-indigo-500 focus:ring-4 focus:ring-indigo-100 outline-none transition-all" placeholder="例如: Aspirin" />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-xs font-black text-slate-400 uppercase mb-1 block">搜尋起始日期</label>
                      <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-2 font-bold outline-none" />
                    </div>
                    <div>
                      <label className="text-xs font-black text-slate-400 uppercase mb-1 block">搜尋結束日期</label>
                      <input type="date" value={input.date_window.to} onChange={e => setInput({...input, date_window: {...input.date_window, to: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-2 font-bold outline-none" />
                    </div>
                  </div>

                  <div>
                    <label className="text-xs font-black text-slate-400 uppercase mb-1 block">不良反應關鍵字</label>
                    <div className="flex flex-wrap gap-2 mb-2">
                      {input.ae_strings.map(ae => (
                        <span key={ae} className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold border border-indigo-100">{ae}</span>
                      ))}
                    </div>
                    <textarea value={input.ae_strings.join(', ')} onChange={e => setInput({...input, ae_strings: e.target.value.split(',').map(s=>s.trim())})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-2 text-sm font-medium focus:border-indigo-500 outline-none" rows={2} />
                  </div>
                </div>

                <div className="bg-amber-50 border border-amber-200 p-4 rounded-2xl flex gap-3 italic text-xs text-amber-700">
                  <ExclamationCircleIcon className="w-5 h-5 flex-shrink-0" />
                  系統將嚴格驗證文獻的發布日期與 ID (PMID/DOI)。不符合者將被強制隔離至待確認區。
                </div>
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="flex-1 flex overflow-hidden">
              {/* List */}
              <div className="w-1/2 overflow-y-auto p-6 space-y-4 border-r border-slate-200">
                <div className="flex justify-between items-end mb-6">
                  <h2 className="text-2xl font-black text-slate-800 tracking-tight">文獻核閱</h2>
                  <span className="text-xs font-bold text-slate-400">發現 {records.length} 筆資料</span>
                </div>

                {records.map(r => (
                  <div 
                    key={r.id} 
                    onClick={() => setSelectedRecordId(r.id)}
                    className={`p-5 rounded-3xl border-2 cursor-pointer transition-all shadow-sm ${selectedRecordId === r.id ? 'border-indigo-600 bg-white ring-4 ring-indigo-50' : 'border-white bg-white hover:border-slate-200'}`}
                  >
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex gap-2">
                        <span className="bg-slate-100 text-slate-500 text-[9px] px-2 py-0.5 rounded font-black uppercase tracking-wider">{r.source}</span>
                        <span className={`text-[9px] px-2 py-0.5 rounded font-black tracking-wider ${r.relevance_score > 70 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                          {r.relevance_score}% PV相關
                        </span>
                      </div>
                      <span className="text-[10px] font-mono text-slate-400">{r.dp}</span>
                    </div>
                    <h3 className="font-bold text-slate-800 leading-tight mb-2 line-clamp-2">{r.title}</h3>
                    <p className="text-xs text-slate-500 line-clamp-2 italic">"{r.summary_zh}"</p>
                  </div>
                ))}
              </div>

              {/* Detail / Verification Panel */}
              <div className="w-1/2 bg-white overflow-y-auto p-8 shadow-inner">
                {selectedRecord ? (
                  <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
                    <div className="flex justify-between items-start">
                      <div className="space-y-1">
                        <div className="flex items-center gap-2 text-indigo-600 text-xs font-black uppercase tracking-widest">
                          <LinkIcon className="w-4 h-4" /> 驗證資料對照模式
                        </div>
                        <h2 className="text-2xl font-black text-slate-800 leading-tight">{selectedRecord.title}</h2>
