import React, { useState, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  ExclamationCircleIcon,
  LinkIcon,
  FingerPrintIcon,
  InformationCircleIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  ArrowTopRightOnSquareIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Diltiazem Hydrochloride'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'unverified' | 'logs'>('review');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setUnverifiedQueue([]);

    try {
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`[稽核] 建立搜尋任務 ${searchMetadata.search_run_id}`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids, fullQuery);

      const masterList: PVRecord[] = [];
      const unverifiable: PVRecord[] = [];

      rawRecords.forEach(r => {
        const pubDate = new Date(r.dp || '');
        const fromDate = new Date(input.date_window.from);
        const toDate = new Date(input.date_window.to);

        const qFlags: string[] = [];
        if (!r.dp) qFlags.push('MISSING_DATE');
        if (!r.pmid && !r.doi) qFlags.push('NO_IDENTITY');

        const record: PVRecord = {
          id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
          source: 'pubmed',
          pmid: r.pmid,
          doi: r.doi,
          title: r.title,
          authors: r.authors,
          journal: r.journal,
          year: r.year,
          dp: r.dp,
          abstract: r.abstract,
          full_text: r.full_text,
          primary_link: r.pubmed_url || r.journal_url || '',
          quality_flags: qFlags,
          relevance_score: 0,
          relevance_reason: '',
          is_excluded: false
        };

        if (qFlags.length > 0 || pubDate < fromDate || pubDate > toDate) {
          record.exclusion_reason = pubDate < fromDate ? "OUT_OF_WINDOW" : "VERIFICATION_FAILED";
          unverifiable.push(record);
        } else {
          masterList.push(record);
        }
      });

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi, idx) => {
        const webRec: PVRecord = {
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: [],
          relevance_score: 0,
          relevance_reason: 'Regulatory search',
          is_excluded: false,
          abstract: gi.snippet,
          full_text: `[REGOULATORY CONTENT] ${gi.snippet}\n\nThis is a simulation of a government regulatory page.`
        };
        masterList.push(webRec);
      });

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));

      setStep(WorkflowStep.SUMMARIZATION);
      const toSummary = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || '' };
      });

      const summaries = await gemini.generateSummaries(toSummary.filter(m => m.relevance_score > 30).map(m => ({ id: m.id, abstract: m.abstract || m.title })));

      const finalRecords = toSummary.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || "未達摘要門檻" };
      });

      setRecords(finalRecords);
      setUnverifiedQueue(unverifiable);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，共發現 ${finalRecords.length} 筆有效文獻。`);
    } catch (e) {
