/**
 * 模擬確定性資料產生器
 * 解決「連結外部資料對不起來」或「法規頁面不存在」的問題，提供高品質模擬全文與快照
 */

const generateMockData = (ingredient: string, id: string) => {
  const seeds: Record<string, any> = {
    "1": {
      title: `Serious bullous drug eruption associated with ${ingredient}: A rare clinical observation`,
      abstract: `We report a case of a 54-year-old female who developed generalized bullous lesions 10 days after starting ${ingredient}. Skin biopsy confirmed toxic epidermal necrolysis. The patient recovered after discontinuation of ${ingredient} and systemic corticosteroid therapy. Naranjo score: 7 (Probable).`,
      full_text: `INTRODUCTION: ${ingredient} is a calcium channel blocker widely used for hypertension and angina pectoris. While generally well-tolerated, rare cutaneous adverse reactions have been reported. 

CASE REPORT: A 54-year-old female with a history of hypertension was initiated on ${ingredient} (30mg TID). On the 10th day of treatment, she presented to the emergency department with painful erythema and bullous lesions covering approximately 35% of her body surface area. Laboratory findings showed elevated CRP levels but were otherwise unremarkable.

METHODS: Skin punch biopsy was performed from a fresh bulla on the left thigh. Histopathological examination revealed subepidermal cleavage and full-thickness epidermal necrosis, consistent with toxic epidermal necrolysis (TEN).

CONCLUSION: Clinicians should remain vigilant for early signs of severe cutaneous reactions when prescribing ${ingredient}. Prompt withdrawal is critical for patient survival.`,
      doi: `10.1016/j.pv.${id}`,
      date: "2025-05-12"
    },
    "2": {
      title: `Potential signal of acute bradycardia and hypotension induced by intravenous ${ingredient}`,
      abstract: `Post-marketing surveillance identified cases of biopsy-proven acute cardiovascular collapse in patients receiving ${ingredient} infusion for supraventricular tachycardia. All patients showed improvement upon withdrawal.`,
      full_text: `BACKGROUND: Intravenous ${ingredient} is commonly used for rapid heart rate control. However, excessive pharmacodynamic effects may lead to severe hypotension.

RESULTS: Between January and March 2025, three patients (age 65-78) experienced sudden symptomatic bradycardia (HR < 40 bpm) and hypotension (SBP < 80 mmHg) within 15 minutes of ${ingredient} administration. 

DISCUSSION: The temporal relationship and positive de-challenge support a causal link between the drug and the cardiovascular events. Dose adjustment in elderly patients is highly recommended.`,
      doi: `10.1111/j.re.2025.${id}`,
      date: "2025-08-20"
    }
  };

  return seeds[id] || {
    title: `Safety evaluation of ${ingredient} in long-term observational study`,
    abstract: `This study analyzes the overall safety profile of ${ingredient}. No significant new safety signals were detected during the 12-month follow-up.`,
    full_text: `FULL TEXT PREVIEW: This long-term study monitored 1,200 patients treated with ${ingredient}. Common side effects included peripheral edema (3.2%) and headache (1.5%). No serious adverse events leading to discontinuation were recorded.`,
    doi: `10.9999/null.${id}`,
    date: "2025-01-01"
  };
};

export const pubmed_build_rss_url = (query: string, limit: number = 100) => {
  const encodedQuery = encodeURIComponent(query);
  return { 
    search_run_id: `PV-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
    rss_url: `https://pubmed.ncbi.nlm.nih.gov/rss/search/1${encodedQuery}/`,
    pubmed_query: query
  };
};

export const pubmed_fetch_rss = async (rss_url: string, query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
  const ingredient = keywords[0];

  await new Promise(r => setTimeout(r, 500));
  return {
    items: [
      { 
        title: generateMockData(ingredient, "1").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800001/", 
        pubDate: generateMockData(ingredient, "1").date,
        guid: "38800001"
      },
      { 
        title: generateMockData(ingredient, "2").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800002/", 
        pubDate: generateMockData(ingredient, "2").date,
        guid: "38800002"
      }
    ]
  };
};

export const pubmed_efetch = async (pmids: string[], query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
  const ingredient = keywords[0];

  await new Promise(r => setTimeout(r, 800));
  return {
    records: pmids.map(id => {
      const seedId = id.endsWith("1") ? "1" : "2";
      const data = generateMockData(ingredient, seedId);
      return {
        pmid: id,
        doi: data.doi,
        title: data.title,
        authors: ["Dr. Anderson", "Prof. Tanaka"],
        journal: "Global Pharmacovigilance Quarterly",
        year: "2025",
        dp: data.date,
        edat: data.date,
        abstract: data.abstract,
        full_text: data.full_text,
        pubmed_url: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
        journal_url: `https://publisher.com/article/${id}`
      };
    })
  };
};

export const google_search = async (query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
  const ingredient = keywords[0];

  // 為 Google 搜尋結果也提供模擬全文 (Snapshot)
  return {
    items: [
      { 
        title: `Regulatory Alert: ${ingredient} and risk of hepatotoxicity`, 
        url: `https://www.tfda.gov.tw/safety/alert-${ingredient.replace(/\s+/g, '-')}`, 
        snippet: `TFDA has received multiple reports of liver injury associated with ${ingredient} use. Healthcare providers are advised to monitor LFTs...`, 
        displayLink: "tfda.gov.tw", 
        date: "2025-06-01",
