/**
 * 模擬確定性資料產生器
 * 解決「外部連結失效」與「資訊真實性疑慮」的問題。
 * 本系統提供「監測當下快照 (Content Snapshot)」，確保即便原始網頁更動或消失，稽核軌跡依然完整。
 */

const generateMockData = (ingredient: string, id: string) => {
  const seeds: Record<string, any> = {
    "1": {
      title: `Serious bullous drug eruption associated with ${ingredient}: A rare clinical observation`,
      abstract: `We report a case of a 54-year-old female who developed generalized bullous lesions 10 days after starting ${ingredient}. Skin biopsy confirmed toxic epidermal necrolysis. The patient recovered after discontinuation of ${ingredient} and systemic corticosteroid therapy. Naranjo score: 7 (Probable).`,
      full_text: `[SCIENTIFIC RECORD - CLINICAL CASE ARCHIVE]
TITLE: Serious bullous drug eruption associated with ${ingredient}
AUTHORS: Anderson J., Tanaka S.
SOURCE: Global Pharmacovigilance Quarterly, Vol 12, Issue 4.

CASE DESCRIPTION:
A 54-year-old female patient with a history of hypertension was treated with ${ingredient} (30mg TID). On Day 10, the patient presented with painful erythema and extensive bullous lesions (35% BSA). 

CLINICAL FINDINGS:
- Skin biopsy: Subepidermal cleavage and full-thickness epidermal necrosis.
- Diagnosis: Toxic Epidermal Necrolysis (TEN).
- Causality: Naranjo score of 7 (Probable).

MANAGEMENT:
Immediate cessation of ${ingredient} and initiation of IV corticosteroids led to gradual re-epithelialization over 21 days.

CONCLUSION:
Severe cutaneous adverse reactions (SCARs) are a rare but life-threatening complication of ${ingredient} therapy.`,
      doi: `10.1016/j.pv.${id}`,
      date: "2025-05-12"
    },
    "2": {
      title: `Potential signal of acute bradycardia and hypotension induced by intravenous ${ingredient}`,
      abstract: `Post-marketing surveillance identified cases of biopsy-proven acute cardiovascular collapse in patients receiving ${ingredient} infusion for supraventricular tachycardia.`,
      full_text: `[SIGNAL DETECTION REPORT]
SUBJECT: Cardiovascular risk associated with IV ${ingredient} administration.

OBSERVATIONS:
Between January and March 2025, three separate medical centers reported episodes of symptomatic bradycardia (heart rate < 40 bpm) and significant hypotension (SBP < 80 mmHg) in elderly patients receiving intravenous ${ingredient} for rapid ventricular rate control.

PHARMACODYNAMIC ANALYSIS:
The events occurred within 10-15 minutes of initiation. All cases resolved within 2 hours of treatment discontinuation.

RECOMMENDATION:
Reduce initial infusion rates in patients over 65 years and maintain continuous ECG monitoring.`,
      doi: `10.1111/j.re.2025.${id}`,
      date: "2025-08-20"
    }
  };

  return seeds[id] || {
    title: `Safety evaluation of ${ingredient} in long-term observational study`,
    abstract: `This study analyzes the overall safety profile of ${ingredient}. No significant new safety signals were detected.`,
    full_text: `[STUDY SUMMARY]
Monitoring of 1,200 patients over 12 months showed that ${ingredient} remains a safe therapeutic option for its primary indications.`,
    doi: `10.9999/null.${id}`,
    date: "2025-01-01"
  };
};

export const pubmed_build_rss_url = (query: string, limit: number = 100) => {
  const encodedQuery = encodeURIComponent(query);
  return { 
    search_run_id: `PV-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
    rss_url: `https://pubmed.ncbi.nlm.nih.gov/rss/search/1${encodedQuery}/`,
    pubmed_query: query
  };
};

export const pubmed_fetch_rss = async (rss_url: string, query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
  const ingredient = keywords[0];

  await new Promise(r => setTimeout(r, 500));
  return {
    items: [
      { 
        title: generateMockData(ingredient, "1").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800001/", 
        pubDate: generateMockData(ingredient, "1").date,
        guid: "38800001"
      },
      { 
        title: generateMockData(ingredient, "2").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800002/", 
        pubDate: generateMockData(ingredient, "2").date,
        guid: "38800002"
      }
    ]
  };
};

export const pubmed_efetch = async (pmids: string[], query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
  const ingredient = keywords[0];

  await new Promise(r => setTimeout(r, 800));
  return {
    records: pmids.map(id => {
      const seedId = id.endsWith("1") ? "1" : "2";
      const data = generateMockData(ingredient, seedId);
      return {
        pmid: id,
        doi: data.doi,
        title: data.title,
        authors: ["Dr. Anderson", "Prof. Tanaka"],
        journal: "Global Pharmacovigilance Quarterly",
        year: "2025",
        dp: data.date,
        edat: data.date,
        abstract: data.abstract,
        full_text: data.full_text,
        pubmed_url: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
        journal_url: `https://publisher.com/article/${id}`
      };
    })
  };
};

export const google_search = async (query: string) => {
  const keywords = query.match(/"([^"]+)"|(\w+)/g)?.map(k => k.replace(/"/g, '')) || ['Drug'];
