          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-12 bg-[#fdfdfd]">
          <div className="max-w-2xl mx-auto space-y-8">
            <div className={`border-b-4 ${record.source === 'web' ? 'border-amber-500' : 'border-indigo-900'} pb-4`}>
              <div className="flex justify-between items-center mb-4">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-tighter ${record.source === 'web' ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-indigo-100 text-indigo-700 border border-indigo-200'}`}>
                  {record.source === 'web' ? 'Official Regulatory Alert' : 'Peer-Reviewed Scientific Content'}
                </span>
                <div className="flex items-center gap-1.5 text-[11px] text-green-700 font-black bg-green-50 px-3 py-1 rounded-full border border-green-100">
                  <CameraIcon className="w-4 h-4" /> SECURE SNAPSHOT: {record.dp || '2025-06-01'}
                </div>
              </div>
              <h1 className="text-3xl font-serif font-bold text-slate-900 leading-tight mb-4">{record.title}</h1>
              <div className="text-sm font-bold text-slate-500 flex gap-4">
                {record.source === 'pubmed' ? (
                  <span>Source: {record.journal} (PMID: {record.pmid})</span>
                ) : (
                  <span>Source: Taiwan Food and Drug Administration (TFDA)</span>
                )}
              </div>
            </div>

            <div className="grid grid-cols-1 gap-8 text-slate-800 font-serif leading-relaxed text-lg">
               <div className="bg-slate-50 p-6 rounded-2xl border-2 border-slate-100 italic text-slate-600 text-sm">
                  <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <DocumentMagnifyingGlassIcon className="w-4 h-4" /> Meta-Summary (Snippet)
                  </h2>
                  "{record.abstract}"
               </div>

               <div className={`p-8 rounded-3xl border-2 shadow-sm ${record.source === 'web' ? 'bg-amber-50/20 border-amber-100' : 'bg-white border-slate-200'}`}>
                  <h2 className={`text-xs font-black uppercase tracking-widest mb-6 flex items-center gap-2 ${record.source === 'web' ? 'text-amber-700' : 'text-indigo-600'}`}>
                     {record.source === 'web' ? <ShieldExclamationIcon className="w-5 h-5" /> : <InformationCircleIcon className="w-5 h-5" />}
                     內部稽核全文存檔 (Full Content Audit Trail)
