import React, { useState, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  db_mark_excluded, 
  export_csv_ingredient_view, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  TrashIcon, 
  ArrowPathIcon,
  DocumentArrowDownIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  ExclamationCircleIcon,
  LinkIcon,
  FingerPrintIcon,
  InformationCircleIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  ArrowTopRightOnSquareIcon,
  ShieldExclamationIcon,
  CameraIcon,
  LockClosedIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Diltiazem Hydrochloride'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [unverifiedQueue, setUnverifiedQueue] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'logs'>('review');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);

    try {
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`[稽核] 建立搜尋任務 ${searchMetadata.search_run_id}`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids, fullQuery);

      const masterList: PVRecord[] = rawRecords.map(r => ({
        id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
        source: 'pubmed',
        pmid: r.pmid,
        doi: r.doi,
        title: r.title,
        authors: r.authors,
        journal: r.journal,
        year: r.year,
        dp: r.dp,
        abstract: r.abstract,
        full_text: r.full_text,
        primary_link: r.pubmed_url || r.journal_url || '',
        quality_flags: [],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false
      }));

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi: any, idx) => {
        masterList.push({
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: ['AUDITED_SNAPSHOT'],
          relevance_score: 0,
          relevance_reason: 'Official Regulatory Content',
          is_excluded: false,
          abstract: gi.snippet,
          full_text: gi.full_text || `[SNAPSHOT] ${gi.snippet}`
        });
      });

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));

      setStep(WorkflowStep.SUMMARIZATION);
      const scored = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || '' };
      });

      const summaries = await gemini.generateSummaries(scored.filter(m => m.relevance_score > 30).map(m => ({ id: m.id, abstract: m.abstract || m.title })));

      const finalRecords = scored.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || "未達摘要門檻" };
      });

      setRecords(finalRecords);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，共獲取 ${finalRecords.length} 筆已驗證快照。`);
    } catch (e) {
      addLog(`[錯誤] 流程中斷: ${e instanceof Error ? e.message : '未知錯誤'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const selectedRecord = records.find(r => r.id === selectedRecordId);

  const JournalPreview = ({ record }: { record: PVRecord }) => (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm">
      <div className="bg-white w-full max-w-4xl h-[90vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden">
        <div className="bg-slate-50 border-b p-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <LockClosedIcon className="w-5 h-5 text-green-600" />
            <span className="text-sm font-black text-slate-700 tracking-widest uppercase">稽核對照證據存檔 (Audit Snapshot)</span>
          </div>
          <button onClick={() => setIsPreviewOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <XMarkIcon className="w-6 h-6 text-slate-500" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-12 bg-[#fdfdfd]">
          <div className="max-w-2xl mx-auto space-y-8">
            <div className={`border-b-4 ${record.source === 'web' ? 'border-amber-500' : 'border-indigo-900'} pb-4`}>
              <div className="flex justify-between items-center mb-4">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${record.source === 'web' ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-indigo-100 text-indigo-700 border border-indigo-200'}`}>
                  {record.source === 'web' ? 'Regulatory Snapshot' : 'Scientific Journal'}
                </span>
                <div className="flex items-center gap-1.5 text-[11px] text-green-700 font-black bg-green-50 px-3 py-1 rounded-full border border-green-100">
                  <CameraIcon className="w-4 h-4" /> SECURE SNAPSHOT: 2025-06-01
                </div>
              </div>
              <h1 className="text-3xl font-serif font-bold text-slate-900 leading-tight mb-4">{record.title}</h1>
              <p className="text-sm font-bold text-slate-500">{record.source === 'web' ? 'Source: TFDA Official' : `Journal: ${record.journal}`}</p>
            </div>

