import React, { useState, useMemo } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
} from './types';
import { 
  pubmed_build_rss_url, 
  pubmed_fetch_rss, 
  pubmed_efetch, 
  google_search, 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  MagnifyingGlassIcon, 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  ArrowTopRightOnSquareIcon,
  ShieldExclamationIcon,
  CameraIcon,
  LockClosedIcon,
  CircleStackIcon,
  FunnelIcon,
  ArrowDownTrayIcon,
  FingerPrintIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Diltiazem Hydrochloride'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>([]); // 真正的主資料庫
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('review');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchRunInfo, setSearchRunInfo] = useState<{id: string, query: string} | null>(null);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  // 資料庫篩選器狀態
  const [dbFilters, setDbFilters] = useState({
    ingredient: '',
    dateFrom: '',
    dateTo: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const fullQuery = `("${input.active_ingredients.join('" OR "')}") AND (${input.ae_strings.join(' OR ')})`;
      const searchMetadata = pubmed_build_rss_url(fullQuery);
      setSearchRunInfo({ id: searchMetadata.search_run_id, query: searchMetadata.pubmed_query });
      addLog(`[稽核] 建立搜尋任務 ${searchMetadata.search_run_id}`);

      setStep(WorkflowStep.RSS_FETCH);
      const { items } = await pubmed_fetch_rss(searchMetadata.rss_url, fullQuery);
      const pmids = items.map(i => i.guid).filter(Boolean) as string[];

      setStep(WorkflowStep.EFETCH_FILTER);
      const { records: rawRecords } = await pubmed_efetch(pmids, fullQuery);

      const masterList: PVRecord[] = rawRecords.map(r => ({
        id: r.pmid ? `pmid-${r.pmid}` : `doi-${r.doi}`,
        source: 'pubmed',
        pmid: r.pmid,
        doi: r.doi,
        title: r.title,
        authors: r.authors,
        journal: r.journal,
        year: r.year,
        dp: r.dp,
        abstract: r.abstract,
        full_text: r.full_text,
        primary_link: r.pubmed_url || r.journal_url || '',
        quality_flags: [],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false
      }));

      setStep(WorkflowStep.WEB_SEARCH);
      const { items: googleItems } = await google_search(fullQuery);
      googleItems.forEach((gi: any, idx: number) => {
        masterList.push({
          id: `web-${idx}`,
          source: 'web',
          title: gi.title,
          primary_link: gi.url,
          quality_flags: ['AUDITED_SNAPSHOT'],
          relevance_score: 0,
          relevance_reason: 'Official Regulatory Content',
          is_excluded: false,
          abstract: gi.snippet,
          full_text: gi.full_text || `[SNAPSHOT] ${gi.snippet}`
        });
      });

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList.map(m => ({ id: m.id, title: m.title, abstract: m.abstract })));

      const scored = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 0, relevance_reason: s?.reason || '' };
      });

      const summaries = await gemini.generateSummaries(scored.filter(m => m.relevance_score > 20).map(m => ({ id: m.id, abstract: m.abstract || m.title })));

      const finalRecords = scored.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || "未達摘要門檻" };
      });

      setRecords(finalRecords);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，已擷取 ${finalRecords.length} 筆待核閱資料。`);
    } catch (e) {
      addLog(`[錯誤] 流程中斷: ${e instanceof Error ? e.message : '未知錯誤'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    // 呼叫工具模擬存入 DB
    await db_upsert([record]);

    // 更新本地主資料庫狀態
    setMasterDatabase(prev => {
      if (prev.find(r => r.id === record.id)) return prev;
      return [...prev, { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] }];
    });

    // 從待核閱清單移除或標記
    setRecords(prev => prev.filter(r => r.id !== record.id));
    setSelectedRecordId(null);
    addLog(`[主資料庫] 已正式匯入文獻: ${record.title}`);
    alert('資料已成功匯入主資料庫，可至「主資料庫」分頁進行篩選與匯出。');
  };

  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const matchIngredient = !dbFilters.ingredient || r.title.toLowerCase().includes(dbFilters.ingredient.toLowerCase()) || (r.abstract || '').toLowerCase().includes(dbFilters.ingredient.toLowerCase());
      const recordDate = r.dp ? new Date(r.dp) : null;
      const matchFrom = !dbFilters.dateFrom || (recordDate && recordDate >= new Date(dbFilters.dateFrom));
      const matchTo = !dbFilters.dateTo || (recordDate && recordDate <= new Date(dbFilters.dateTo));
      return matchIngredient && matchFrom && matchTo;
    });
  }, [masterDatabase, dbFilters]);

  const selectedRecord = records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId);

  const JournalPreview = ({ record }: { record: PVRecord }) => (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm">
      <div className="bg-white w-full max-w-4xl h-[90vh] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="bg-slate-50 border-b p-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <LockClosedIcon className="w-5 h-5 text-green-600" />
            <span className="text-sm font-black text-slate-700 uppercase tracking-widest">PV Evidence Snapshot</span>
          </div>
          <button onClick={() => setIsPreviewOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <XMarkIcon className="w-6 h-6 text-slate-500" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-12 bg-[#fdfdfd]">
          <div className="max-w-2xl mx-auto space-y-8">
            <div className={`border-b-4 ${record.source === 'web' ? 'border-amber-500' : 'border-indigo-900'} pb-4`}>
              <div className="flex justify-between items-center mb-4">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${record.source === 'web' ? 'bg-amber-100 text-amber-700' : 'bg-indigo-100 text-indigo-700'}`}>
                  {record.source === 'web' ? 'Regulatory' : 'Scientific'}
                </span>
                <div className="flex items-center gap-1.5 text-[11px] text-green-700 font-black">
                  <CameraIcon className="w-4 h-4" /> SECURE SNAPSHOT: {record.dp || '2025'}
                </div>
              </div>
              <h1 className="text-2xl font-serif font-bold text-slate-900 leading-tight mb-4">{record.title}</h1>
            </div>
            <div className="space-y-6">
              <div className="bg-slate-50 p-6 rounded-2xl border-2 border-slate-100 italic text-slate-600 text-sm whitespace-pre-wrap leading-relaxed">
                {record.full_text || record.abstract}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-gray-100 text-slate-900">
      {isPreviewOpen && selectedRecord && <JournalPreview record={selectedRecord} />}

      <div className="bg-slate-950 text-slate-500 text-[10px] px-4 py-1 flex justify-between font-mono">
        <span>PV-AUDIT-TRACKER // DB_SIZE: {masterDatabase.length}</span>
        <span>STAMP: {now().iso_datetime}</span>
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg shadow-indigo-200">
            <ShieldCheckIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight">PV-Link Auditor</h1>
            <p className="text-xs text-slate-400 font-medium">藥品安全監測代理人系統</p>
          </div>
        </div>
        <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-5 py-2.5 rounded-xl text-sm font-bold shadow-md flex items-center gap-2 transition-all active:scale-95">
          {isProcessing ? <ArrowPathIcon className="w-4 h-4 animate-spin" /> : <MagnifyingGlassIcon className="w-4 h-4" />}
          啟動監測流程
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-64 bg-white border-r border-slate-200 flex flex-col">
          <div className="p-4 space-y-1">
            <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'input' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>
              <QueueListIcon className="w-5 h-5" /> 監控配置
            </button>
            <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'review' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>
              <ClipboardDocumentCheckIcon className="w-5 h-5" /> 文獻核閱 ({records.length})
            </button>
            <button onClick={() => setActiveTab('database')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'database' ? 'bg-green-50 text-green-700' : 'text-slate-500 hover:bg-slate-50'}`}>
              <CircleStackIcon className="w-5 h-5" /> 主資料庫 ({masterDatabase.length})
            </button>
            <button onClick={() => setActiveTab('logs')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'logs' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>
              <FingerPrintIcon className="w-5 h-5" /> 稽核日誌
            </button>
          </div>
        </aside>

        <section className="flex-1 overflow-y-auto flex bg-slate-50">
          {activeTab === 'input' && (
