                <div className="space-y-4">
                  <div>
                    <label className="text-xs font-black text-slate-400 uppercase mb-2 block tracking-widest">藥品主成分 (API)</label>
                    <input type="text" value={input.active_ingredients[0]} onChange={e => setInput({...input, active_ingredients: [e.target.value]})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-4 text-lg font-bold outline-none focus:border-indigo-500 transition-all" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-xs font-black text-slate-400 mb-1 block">起始日期</label>
                      <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-4 py-3 font-bold outline-none" />
                    </div>
