const generateMockData = (ingredient: string, id: string) => {
  const seeds: Record<string, any> = {
    "1": {
      title: `Potential association between ${ingredient} and severe bullous skin reactions`,
      abstract: `This case series describes three patients who developed serious cutaneous adverse reactions shortly after initiating therapy with ${ingredient}. Histopathology was consistent with Stevens-Johnson Syndrome. Causality assessment using Naranjo scale indicated a 'probable' relationship.`,
      full_text: `[CASE ARCHIVE - AUDIT READY]\nSUBJECT: ${ingredient} and SJS\n\nClinical presentation: Extensive mucosal erosions and skin detachment observed in a 62-year-old male taking ${ingredient} 200mg daily. \nResolution: Event resolved after treatment with systemic steroids and discontinuation of ${ingredient}.`,
      doi: `10.1016/j.pv.${ingredient.toLowerCase()}.${id}`,
      date: "2025-05-12"
    },
    "2": {
      title: `Elevated liver enzymes and muscle toxicity during ${ingredient} therapy: A signal detection`,
      abstract: `Post-marketing analysis of 45 cases of myopathy and rhabdomyolysis in patients concurrently taking ${ingredient} and HMG-CoA reductase inhibitors. Combined therapy significantly increases the risk of CPK elevation.`,
      full_text: `[SIGNAL DETECTION REPORT]\nINGREDIENT: ${ingredient}\n\nSummary: Monitoring of LFTs and CPK levels is highly recommended for patients on stable ${ingredient} regimens. Risk of interaction with statins is highlighted.`,
      doi: `10.1111/j.re.2025.${ingredient.toLowerCase()}.${id}`,
      date: "2025-08-20"
    }
  };

  return seeds[id] || {
    title: `Safety profile update for ${ingredient}: 2025 Review`,
    abstract: `An overview of common side effects associated with ${ingredient}, including gastrointestinal upset and mild headache. No new safety signals identified.`,
    full_text: `[ANNUAL REVIEW] ${ingredient} continues to show a favorable benefit-risk ratio.`,
    doi: `10.9999/null.${id}`,
    date: "2025-01-01"
  };
};

export const pubmed_build_rss_url = (query: string, limit: number = 100) => {
  const encodedQuery = encodeURIComponent(query);
  return { 
    search_run_id: `PV-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
    rss_url: `https://pubmed.ncbi.nlm.nih.gov/rss/search/1${encodedQuery}/`,
    pubmed_query: query
  };
};

export const pubmed_fetch_rss = async (rss_url: string, query: string) => {
  // 改進的關鍵字提取：尋找括號內或引號內的藥品名
  const ingredientMatch = query.match(/\("([^"]+)"\)|"([^"]+)"|(\b\w+\b)/);
  const ingredient = ingredientMatch ? (ingredientMatch[1] || ingredientMatch[2] || ingredientMatch[3]) : 'Drug';

  await new Promise(r => setTimeout(r, 500));
  return {
    items: [
      { 
        title: generateMockData(ingredient, "1").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800001/", 
        pubDate: generateMockData(ingredient, "1").date,
        guid: "38800001"
      },
      { 
        title: generateMockData(ingredient, "2").title,
        link: "https://pubmed.ncbi.nlm.nih.gov/38800002/", 
        pubDate: generateMockData(ingredient, "2").date,
        guid: "38800002"
      }
    ]
  };
};

export const pubmed_efetch = async (pmids: string[], query: string) => {
  const ingredientMatch = query.match(/\("([^"]+)"\)|"([^"]+)"|(\b\w+\b)/);
  const ingredient = ingredientMatch ? (ingredientMatch[1] || ingredientMatch[2] || ingredientMatch[3]) : 'Drug';

  await new Promise(r => setTimeout(r, 800));
  return {
    records: pmids.map(id => {
      const seedId = id.endsWith("1") ? "1" : "2";
      const data = generateMockData(ingredient, seedId);
      return {
        pmid: id,
        doi: data.doi,
        title: data.title,
        authors: ["PV Research Team"],
        journal: "Global Safety Journal",
        year: "2025",
        dp: data.date,
        edat: data.date,
        abstract: data.abstract,
        full_text: data.full_text,
        pubmed_url: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
        journal_url: `https://publisher.com/article/${id}`
