import { GoogleGenAI, Type } from "@google/genai";

export class PVGeminiService {
  private get ai() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * 使用 Google Search Grounding 執行真實搜尋
   */
  async performRealSearch(query: string, ingredient: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `你是一個專業的藥物安全監測 (PV) 專家。
        請針對藥物成分「${ingredient}」執行以下搜尋：
        搜尋指令：${query}
        請尋找：
        1. 最近一年的 PubMed 文獻 (Case Reports, Clinical Trials)
        2. 監管機構 (FDA, EMA, TFDA) 的安全警訊
        3. 專業醫學期刊上的不良反應報告

        請將搜尋結果整理成 JSON 格式回傳，格式如下：
        [
          {
            "id": "來源唯一碼",
            "title": "文獻或公告標題",
            "source_type": "pubmed" | "regulatory" | "journal",
            "date": "YYYY-MM-DD",
            "summary": "簡短摘要 (繁體中文)",
            "url": "真實的來源連結"
          }
        ]
        請確保回傳內容為純 JSON 陣列，不要有 Markdown 標記。`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        },
      });

      // 嘗試解析 JSON
      const text = response.text.trim();
      const results = JSON.parse(text);

      // 提取 Grounding 元數據作為稽核證據
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      return {
        data: results,
        grounding: groundingChunks
      };
    } catch (e) {
      console.error("Real Search Error:", e);
      throw e;
    }
  }

  async scoreRelevance(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Evaluate pharmacovigilance (PV) relevance. Score 0-100.
        Records: ${JSON.stringify(records.map(r => ({ id: r.id, title: r.title, abstract: r.abstract })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                score: { type: Type.NUMBER },
                reason: { type: Type.STRING }
              },
              required: ["id", "score", "reason"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      console.error("Score Error:", e);
      return records.map(r => ({ id: r.id, score: 50, reason: "AI 評分暫時無法使用" }));
    }
  }

  async generateSummaries(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `為以下藥品安全文獻產出繁體中文摘要。
        文獻： ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                summary_zh: { type: Type.STRING }
              },
              required: ["id", "summary_zh"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ id: r.id, summary_zh: "摘要生成中..." }));
    }
  }

  async extractPVData(record: any) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Extract PV data from: ${record.abstract || record.title}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              product: { type: Type.STRING },
              ingredient: { type: Type.STRING },
              ae_verbatim: { type: Type.STRING },
              meddra_pt_candidate: { type: Type.STRING },
              meddra_confidence: { type: Type.NUMBER },
              seriousness: { type: Type.STRING },
              population: { type: Type.STRING },
              dosage_route: { type: Type.STRING },
              tto: { type: Type.STRING },
              outcome: { type: Type.STRING },
              causality: { type: Type.STRING },
              completeness: { type: Type.STRING }
            }
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { product: "N/A", completeness: "Missing" };
    }
  }
}

