const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2024-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'adverse reaction', 'toxicity', 'side effect'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  const [dbFilters, setDbFilters] = useState({
    ingredient: '',
    dateFrom: '',
    dateTo: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setSelectedRecordId(null);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const fullQuery = `"${ingredient}" AND (${input.ae_strings.join(' OR ')}) recent literature and safety alerts from PubMed FDA EMA TFDA`;
      addLog(`[稽核] 發起真實聯網搜尋: ${ingredient}`);

      setStep(WorkflowStep.WEB_SEARCH);
      addLog(`[Google Search] 正在存取全球藥物監測數據庫...`);
      const { data: realResults, grounding } = await gemini.performRealSearch(fullQuery, ingredient);

      const masterList: PVRecord[] = realResults.map((r: any, idx: number) => ({
        id: r.id || `real-${idx}`,
        source: r.source_type === 'pubmed' ? 'pubmed' : 'web',
        title: r.title,
        dp: r.date,
        abstract: r.summary,
        full_text: `[REAL-TIME AUDIT CONTENT]\nURL: ${r.url}\n\nSUMMARY: ${r.summary}\n\n這是一筆來自真實網路搜尋的資料，請核對連結內容。`,
        primary_link: r.url,
        quality_flags: ['REAL_TIME_GROUNDING'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false
      }));

      setStep(WorkflowStep.RELEVANCE_SCORING);
      const scores = await gemini.scoreRelevance(masterList);

      const scored = masterList.map(m => {
        const s = scores.find((sc: any) => sc.id === m.id);
        return { ...m, relevance_score: s?.score || 50, relevance_reason: s?.reason || 'AI 評分完畢' };
      });

      setStep(WorkflowStep.SUMMARIZATION);
      const summaries = await gemini.generateSummaries(scored);

      const finalRecords = scored.map(m => {
        const sum = summaries.find((s: any) => s.id === m.id);
        return { ...m, summary_zh: sum?.summary_zh || m.abstract };
      });

      setRecords(finalRecords);
      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
      addLog(`監測完成，成功從網際網路擷取 ${finalRecords.length} 筆真實資料。`);
    } catch (e) {
      addLog(`[錯誤] 搜尋失敗: ${e instanceof Error ? e.message : '請檢查網路連線或 API Key'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    await db_upsert([record]);
    setMasterDatabase(prev => {
      if (prev.find(r => r.id === record.id)) return prev;
      return [...prev, { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] }];
    });
    setRecords(prev => prev.filter(r => r.id !== record.id));
    setSelectedRecordId(null);
    addLog(`[主資料庫] 已匯入文獻: ${record.title}`);
  };

  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const matchIngredient = !dbFilters.ingredient || r.title.toLowerCase().includes(dbFilters.ingredient.toLowerCase());
      const recordDate = r.dp ? new Date(r.dp) : null;
