import { GoogleGenAI, Type } from "@google/genai";

export class PVGeminiService {
  private get ai() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * 鎖定 NCBI PubMed 進行真實聯網搜尋，嚴格要求標題與連結 1:1 精確對位
   */
  async performPubMedSearch(query: string, ingredient: string, dateWindow: { from: string, to: string }) {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `你是一個嚴謹的藥品安全監視 (PV) 稽核代理人。

        任務目標：
        在 NCBI PubMed 上搜尋藥物成分「${ingredient}」的相關文獻。
        搜尋條件：${query}
        監測區間：${dateWindow.from} ~ ${dateWindow.to}

        關鍵合規要求 (防止張冠李戴)：
        1. 標題與連結必須 100% 匹配：請務必檢查你提供的 "title" 是否真的是該 "url" 網頁中的論文標題。嚴禁將 A 論文的標題配上 B 論文的連結。
        2. 嚴禁預測 PMID：如果搜尋結果中沒有明確的 PMID，請直接從原始 URL 中提取。不可自行編造數字。
        3. 內容真實性："summary" 必須摘自該連結對應的真實摘要，不可憑空想像。

        回傳格式 (必須為純 JSON 陣列)：
        [
          {
            "pmid": "真實的PMID (若無則填網址末端ID)",
            "title": "與網址內容完全一致的英文標題",
            "date": "YYYY-MM-DD (出版日期)",
            "journal": "真實期刊名稱",
            "summary": "真實摘要片段",
            "url": "https://pubmed.ncbi.nlm.nih.gov/PMID數字/"
          }
        ]`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        },
      });

      // 檢查 response.text 是否包含有效的 JSON
      const text = response.text.trim();
      const results = JSON.parse(text || '[]');

      // 額外的安全性過濾：確保 URL 包含 pmid
      return results.filter((r: any) => r.url && r.url.includes('pubmed.ncbi.nlm.nih.gov'));
    } catch (e) {
      console.error("PubMed Search Precision Error:", e);
      throw e;
    }
  }

  async scoreRelevance(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Evaluate Pharmacovigilance (PV) relevance (score 0-100) for these records based on potential adverse events: ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pmid: { type: Type.STRING },
                score: { type: Type.NUMBER },
                reason: { type: Type.STRING }
              },
              required: ["pmid", "score", "reason"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ pmid: r.pmid, score: 50, reason: "AI 評分暫時無法使用" }));
    }
  }

  async generateSummaries(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `請將以下 PubMed 文獻摘要翻譯為繁體中文，並從藥物安全監測角度撰寫重點摘要。
        文獻： ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
