import { GoogleGenAI, Type } from "@google/genai";

export class PVGeminiService {
  private get ai() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * 鎖定 NCBI PubMed 進行深度搜尋，要求完整回傳所有搜尋到的文獻，禁止擅自省略。
   */
  async performPubMedSearch(query: string, ingredient: string, dateWindow: { from: string, to: string }) {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `你是一個專業且極度嚴謹的藥品安全監視 (PV) 稽核代理人。

        任務：
        1. 使用 googleSearch 搜尋 NCBI PubMed 上關於「${ingredient}」的文獻。
        2. 搜尋語法：${query}
        3. 監測時間範圍：${dateWindow.from} ~ ${dateWindow.to}

        【重要：完整性與精確性要求】
        - 完整性：請回傳搜尋到的「所有」相關文獻。目標列出 10 到 15 筆結果。不要只列出前 3 筆，不要擅自過濾。
        - 1:1 精確對位：每一筆 JSON 資料的 "title" 必須與 "url" 內容完全一致。嚴禁將 A 論文的標題配上 B 論文的連結（這是嚴重的稽核錯誤）。
        - 來源驗證：僅接受來自 pubmed.ncbi.nlm.nih.gov 的連結。
        - 禁用幻覺：如果連結是 https://pubmed.ncbi.nlm.nih.gov/12345/，則 pmid 就是 12345。嚴禁編造與網址不符的 PMID。

        回傳格式 (純 JSON 陣列，不加任何 Markdown 標籤)：
        [
          {
            "pmid": "從URL提取的PMID",
            "title": "網頁真實英文標題",
            "date": "YYYY-MM-DD",
            "journal": "期刊全名",
            "summary": "原始摘要片段",
            "url": "https://pubmed.ncbi.nlm.nih.gov/PMID數字/"
          }
        ]`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        },
      });

      const text = response.text.trim();
      const results = JSON.parse(text || '[]');

      // 過濾非 PubMed 連結並確保標題存在
      return results.filter((r: any) => 
        r.url && 
        r.url.includes('pubmed.ncbi.nlm.nih.gov') && 
        r.title && 
        r.title.length > 5
      );
    } catch (e) {
      console.error("PubMed Precision Search Error:", e);
      throw e;
    }
  }

  async scoreRelevance(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Evaluate Pharmacovigilance (PV) relevance (score 0-100) for these records based on potential adverse events: ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pmid: { type: Type.STRING },
                score: { type: Type.NUMBER },
                reason: { type: Type.STRING }
              },
              required: ["pmid", "score", "reason"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ pmid: r.pmid, score: 50, reason: "AI 評分暫時無法使用" }));
    }
  }

  async generateSummaries(records: any[]) {
    try {
      // 為了解決長度限制問題，我們批次處理摘要生成
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `請將以下文獻摘要翻譯為繁體中文，並從藥物安全角度進行專業摘要。必須保留對應的 PMID。
        文獻： ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pmid: { type: Type.STRING },
                summary_zh: { type: Type.STRING }
              },
              required: ["pmid", "summary_zh"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ pmid: r.pmid, summary_zh: "摘要生成中..." }));
    }
  }

  async extractPVData(record: any) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `從以下文獻內容中抽取結構化 PV 數據: ${record.summary || record.title}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              product: { type: Type.STRING },
              ingredient: { type: Type.STRING },
              ae_verbatim: { type: Type.STRING },
              meddra_pt_candidate: { type: Type.STRING },
              meddra_confidence: { type: Type.NUMBER },
              seriousness: { type: Type.STRING },
              population: { type: Type.STRING },
              dosage_route: { type: Type.STRING },
              tto: { type: Type.STRING },
              outcome: { type: Type.STRING },
              causality: { type: Type.STRING },
              completeness: { type: Type.STRING }
            }
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { product: "N/A", completeness: "Missing" };
    }
  }
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData
} from './types';
import { 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  ShieldCheckIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  CircleStackIcon,
  FingerPrintIcon,
  SparklesIcon,
  GlobeAltIcon,
  ShieldExclamationIcon,
  BeakerIcon,
  AdjustmentsHorizontalIcon,
  ArrowTopRightOnSquareIcon,
  PlusIcon,
  ListBulletIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['adverse event', 'toxicity', 'side effect', 'case report'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [keywordInput, setKeywordInput] = useState("");
  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleAddKeyword = () => {
    const trimmedKw = keywordInput.trim();
    if (trimmedKw === "") return;
    if (!input.ae_strings.includes(trimmedKw)) {
      setInput(prev => ({ ...prev, ae_strings: [...prev.ae_strings, trimmedKw] }));
      setKeywordInput("");
      addLog(`[設定] 已新增關鍵字: "${trimmedKw}"`);
    } else {
      alert("該關鍵字已存在於清單中。");
    }
  };

  const handleRemoveKeyword = (kw: string) => {
    if (input.ae_strings.length <= 1) {
      alert("至少需保留一個檢索關鍵字。");
      return;
    }
    setInput(prev => ({ ...prev, ae_strings: prev.ae_strings.filter(item => item !== kw) }));
    addLog(`[設定] 已移除關鍵字: "${kw}"`);
  };

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setSelectedRecordId(null);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const aeGroup = input.ae_strings.map(s => `"${s}"`).join(' OR ');
      const pubmedQuery = `("${ingredient}"[MeSH Terms] OR "${ingredient}"[All Fields]) AND (${aeGroup})`;
      addLog(`[稽核] 已生成 PubMed 標準查詢式: ${pubmedQuery}`);

      setStep(WorkflowStep.RSS_FETCH);
      addLog(`[深度監測] 正在透過 PubMed 代理執行廣域檢索...`);

      const realResults = await gemini.performPubMedSearch(pubmedQuery, ingredient, input.date_window);
      addLog(`[完成檢索] 找到 ${realResults.length} 筆原始結果，開始進行對位稽核與日期過濾...`);

      let rawRecords: PVRecord[] = realResults.map((r: any) => ({
        id: r.pmid || `pubmed-${Math.random().toString(36).substr(2, 9)}`,
        source: 'pubmed',
        pmid: r.pmid,
        title: r.title,
        journal: r.journal,
        dp: r.date,
        abstract: r.summary,
        full_text: `[NCBI PubMed Official Record]\nPMID: ${r.pmid}\nJOURNAL: ${r.journal}\nDATE: ${r.date}\n\nSUMMARY: ${r.summary}`,
        primary_link: r.url || `https://pubmed.ncbi.nlm.nih.gov/${r.pmid}/`,
        quality_flags: ['NCBI_FETCHED'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false
      }));

      const startDate = new Date(input.date_window.from);
      const endDate = new Date(input.date_window.to);

      const filteredRecords = rawRecords.map(r => {
        const recordDate = r.dp ? new Date(r.dp) : null;
        if (!recordDate || recordDate < startDate || recordDate > endDate) {
          return { ...r, is_excluded: true, exclusion_reason: 'OUT_OF_WINDOW' };
        }
        return r;
      });

      const validRecords = filteredRecords.filter(r => !r.is_excluded);
      addLog(`[稽核完畢] 通過日期篩選文獻：${validRecords.length} 筆`);

      if (validRecords.length > 0) {
        setStep(WorkflowStep.RELEVANCE_SCORING);
        addLog(`[AI 分析] 正在評估 PV 相關性得分...`);
        const scores = await gemini.scoreRelevance(validRecords);

        setStep(WorkflowStep.SUMMARIZATION);
        addLog(`[AI 分析] 正在生成專業中文藥安摘要...`);
        const summaries = await gemini.generateSummaries(validRecords);

        const finalized = filteredRecords.map(m => {
          if (m.is_excluded) return m;
          const s = scores.find((sc: any) => sc.pmid === m.pmid);
          const sum = summaries.find((su: any) => su.pmid === m.pmid);
          return { 
            ...m, 
            relevance_score: s?.score || 50, 
            relevance_reason: s?.reason || 'AI 分析完成',
            summary_zh: sum?.summary_zh || m.abstract 
          };
        });
        setRecords(finalized);
      } else {
        setRecords(filteredRecords);
      }

      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (e) {
      addLog(`[錯誤] 搜尋異常: ${e instanceof Error ? e.message : '連線中斷'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    await db_upsert([record]);
    setMasterDatabase(prev => [...prev, { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] }]);
    setRecords(prev => prev.filter(r => r.id !== record.id));
    setSelectedRecordId(null);
    addLog(`[資料庫] 已手動匯入正式文獻: PMID:${record.pmid}`);
  };

  const selectedRecord = useMemo(() => 
    records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId)
  , [records, masterDatabase, selectedRecordId]);

  const [isExtracting, setIsExtracting] = useState(false);
  useEffect(() => {
    const triggerExtraction = async () => {
      if (selectedRecord && !selectedRecord.pv_data && !isExtracting && !selectedRecord.is_excluded) {
        setIsExtracting(true);
        const data = await gemini.extractPVData(selectedRecord);
        setRecords(prev => prev.map(r => r.id === selectedRecord.id ? { ...r, pv_data: data } : r));
        setMasterDatabase(prev => prev.map(r => r.id === selectedRecord.id ? { ...r, pv_data: data } : r));
        setIsExtracting(false);
      }
    };
    triggerExtraction();
  }, [selectedRecordId]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans">
      <div className="bg-slate-950 text-indigo-400/60 text-[10px] px-6 py-1.5 flex justify-between font-mono tracking-widest border-b border-slate-800">
        <span>NCBI-PRECISION-LOCKED // BULK-SEARCH-ENABLED</span>
        <span>SYSTEM_TIME: {now().iso_datetime}</span>
      </div>

      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center sticky top-0 z-30 shadow-sm">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-xl shadow-indigo-200">
            <BeakerIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">PV-Link <span className="text-indigo-600">PubMed Auditor</span></h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">
              <GlobeAltIcon className="w-3 h-3" /> NCBI RSS Real-time Agent
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {isProcessing && (
             <div className="text-xs font-black text-indigo-600 animate-pulse bg-indigo-50 px-4 py-2 rounded-full border border-indigo-100 flex items-center gap-2">
               <ArrowPathIcon className="w-3 h-3 animate-spin" /> {step}
             </div>
          )}
          <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-6 py-3 rounded-2xl text-sm font-black shadow-lg shadow-indigo-100 flex items-center gap-2 transition-all active:scale-95">
            <ArrowPathIcon className={`w-5 h-5 ${isProcessing ? 'animate-spin' : ''}`} />
            啟動監測任務
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col p-6 space-y-2">
          <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <AdjustmentsHorizontalIcon className="w-5 h-5" /> 任務參數
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 核閱清單 ({records.filter(r => !r.is_excluded).length})
          </button>
          <button onClick={() => setActiveTab('database')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'database' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <CircleStackIcon className="w-5 h-5" /> 正式資料庫 ({masterDatabase.length})
          </button>
          <div className="mt-auto pt-4 border-t border-slate-100">
            <button onClick={() => setActiveTab('logs')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[10px] font-black transition-all text-slate-400 hover:text-slate-600 uppercase tracking-widest`}>
              <FingerPrintIcon className="w-4 h-4" /> 稽核日誌記錄
            </button>
          </div>
        </aside>

        <section className="flex-1 overflow-hidden flex flex-col">
          {activeTab === 'input' && (
            <div className="flex-1 overflow-y-auto p-12 bg-slate-50/50">
              <div className="max-w-2xl mx-auto space-y-12">
                <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl space-y-10">
                   <div className="flex items-center gap-3">
                     <div className="bg-indigo-100 p-2 rounded-xl text-indigo-600"><BeakerIcon className="w-6 h-6" /></div>
                     <h2 className="text-3xl font-black text-slate-900 tracking-tight">PubMed 檢索配置</h2>
                   </div>
                  <div className="space-y-6">
                    <div className="group">
                      <label className="text-[10px] font-black text-slate-400 uppercase mb-3 block tracking-widest">鎖定主成分 (API)</label>
                      <input type="text" value={input.active_ingredients[0]} onChange={e => setInput({...input, active_ingredients: [e.target.value]})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-[1.5rem] px-6 py-5 text-xl font-black outline-none focus:border-indigo-600 focus:bg-white transition-all shadow-sm" placeholder="例如: Fenofibrate" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 mb-2 block uppercase tracking-widest">日期起始 (From)</label>
                        <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-5 py-4 font-black outline-none focus:border-indigo-600" />
                      </div>
                      <div>
                        <label className="text-[10px] font-black text-slate-400 mb-2 block uppercase tracking-widest">日期結束 (To)</label>
                        <input type="date" value={input.date_window.to} onChange={e => setInput({...input, date_window: {...input.date_window, to: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-5 py-4 font-black outline-none focus:border-indigo-600" />
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 mb-3 block uppercase tracking-widest">不良反應關鍵字</label>
                      <div className="space-y-4">
                        <div className="flex flex-wrap gap-2">
                          {input.ae_strings.map((s, idx) => (
                            <div key={idx} className="group relative">
                              <span className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl text-xs font-black border border-indigo-100 flex items-center gap-2">
                                {s}
                                <button onClick={() => handleRemoveKeyword(s)} className="hover:text-red-500 transition-colors">
                                  <XMarkIcon className="w-3 h-3" />
                                </button>
                              </span>
                            </div>
                          ))}
                        </div>
                        <div className="flex gap-2">
                          <input type="text" value={keywordInput} onChange={(e) => setKeywordInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAddKeyword()} placeholder="輸入新關鍵字..." className="flex-1 bg-slate-50 border-slate-200 border-2 rounded-xl px-4 py-2 text-sm font-black outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                          <button onClick={handleAddKeyword} className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-xs font-black flex items-center gap-1 hover:bg-indigo-700 shadow-md">
                            <PlusIcon className="w-4 h-4" /> 新增
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="flex-1 flex overflow-hidden">
              <div className="w-[45%] overflow-y-auto p-8 space-y-4 border-r border-slate-200 bg-slate-50/50">
                <div className="flex justify-between items-end mb-4">
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">文獻獲取結果</h2>
                  <span className="text-[10px] font-black text-slate-400 bg-white px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">{records.length} Records</span>
                </div>
                {records.length === 0 ? (
                  <div className="h-64 flex flex-col items-center justify-center text-slate-300 gap-4">
                    <BeakerIcon className="w-16 h-16 opacity-20" />
                    <p className="font-black text-sm uppercase tracking-widest">尚未獲取資料</p>
                  </div>
                ) : records.map(r => (
                  <div key={r.id} onClick={() => setSelectedRecordId(r.id)} className={`group p-6 rounded-[2rem] border-2 cursor-pointer transition-all ${selectedRecordId === r.id ? 'border-indigo-600 bg-white ring-8 ring-indigo-50 shadow-xl' : r.is_excluded ? 'border-slate-100 bg-slate-100/50 opacity-60 grayscale' : 'border-white bg-white hover:border-slate-200 shadow-sm'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-2">
