          {activeTab === 'review' && (
            <div className="flex-1 flex overflow-hidden">
              <div className="w-[45%] overflow-y-auto p-8 space-y-4 border-r border-slate-200 bg-slate-50/50">
                <div className="flex justify-between items-end mb-4">
