                    <h3 className="font-black text-slate-800 leading-snug text-sm mb-2 group-hover:text-indigo-600 transition-colors line-clamp-2">{r.title}</h3>
                    <p className="text-[10px] font-bold text-slate-400 truncate italic">{r.journal}</p>
