              </div>

              <div className="flex-1 bg-white overflow-y-auto p-12">
                {selectedRecord ? (
                  <div className="max-w-xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-indigo-600 text-[10px] font-black uppercase tracking-widest"><SparklesIcon className="w-4 h-4" /> PubMed Precise Audit</div>
                      <h2 className="text-2xl font-black text-slate-900 leading-tight">{selectedRecord.title}</h2>
                      <div className="flex gap-3">
                        <button onClick={() => window.open(selectedRecord.primary_link, '_blank')} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[11px] hover:bg-slate-800 transition-all shadow-lg active:scale-95">
                          <ArrowTopRightOnSquareIcon className="w-4 h-4" /> 驗證原始連結 (PMID:{selectedRecord.pmid})
                        </button>
                      </div>
