                    {selectedRecord.is_excluded ? (
                      <div className="bg-red-50 border-2 border-red-100 text-red-900 rounded-[2.5rem] p-10 flex flex-col items-center text-center gap-4">
                         <XMarkIcon className="w-12 h-12 text-red-300" />
                         <h3 className="text-xl font-black">文獻已被自動篩除</h3>
                         <p className="text-sm font-medium italic">此文獻日期為 {selectedRecord.dp}</p>
                      </div>
                    ) : (
                      <>
                        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 text-white rounded-[2.5rem] p-10 shadow-2xl relative">
                          <div className="text-[10px] font-black text-indigo-200 uppercase mb-4 tracking-widest border-b border-indigo-400/30 pb-2 inline-block">AI 藥安解析</div>
                          <p className="text-lg font-bold leading-relaxed">{selectedRecord.summary_zh || "正在分析摘要..."}</p>
                        </div>

                        <div className="space-y-4">
                          <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">結構化數據</div>
                          <div className="bg-slate-50 border border-slate-200 rounded-[2rem] p-8 grid grid-cols-2 gap-6">
                            <div className="space-y-1">
                              <div className="text-[9px] font-black text-slate-400 uppercase">MedDRA Candidate</div>
                              <div className="text-sm font-black text-slate-800">{selectedRecord.pv_data?.meddra_pt_candidate || "正在提取..."}</div>
                            </div>
                            <div className="space-y-1">
                              <div className="text-[9px] font-black text-slate-400 uppercase">PV Relevance</div>
                              <div className="text-sm font-black text-indigo-600">{selectedRecord.relevance_score}% Score</div>
                            </div>
                          </div>
                        </div>

                        <button onClick={() => handleImport(selectedRecord)} className="w-full bg-emerald-600 text-white py-6 rounded-[2rem] font-black hover:bg-emerald-700 shadow-xl text-xl transition-all active:scale-95">
                          匯入正式資料庫
                        </button>
                      </>
                    )}
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-6">
                    <DocumentMagnifyingGlassIcon className="w-20 h-20 opacity-10" />
                    <p className="font-black uppercase tracking-[0.3em] text-[10px]">Select a record to review</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'database' && (
            <div className="w-full h-full bg-slate-50 p-12 overflow-hidden flex flex-col">
              <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-10">正式文獻庫</h2>
              <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl flex-1 overflow-auto">
                <table className="w-full">
                  <thead className="bg-slate-50 sticky top-0 border-b border-slate-100 z-10">
                    <tr>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">PMID</th>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Title</th>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase">Journal</th>
                    </tr>
                  </thead>
                  <tbody>
                    {masterDatabase.map(r => (
                      <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                        <td className="px-8 py-8 font-mono text-xs text-slate-500">{r.pmid}</td>
                        <td className="px-8 py-8 font-black text-slate-800 leading-snug">{r.title}</td>
                        <td className="px-8 py-8 font-bold text-slate-400 text-sm italic">{r.journal}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="w-full h-full bg-slate-950 p-12 overflow-hidden flex flex-col">
              <h2 className="text-2xl font-black text-indigo-400 tracking-tight mb-8">系統稽核日誌</h2>
              <div className="flex-1 bg-black/60 rounded-[2rem] p-10 font-mono text-[11px] text-indigo-300/80 overflow-y-auto border border-white/5">
                {logs.map((l, i) => (
                  <div key={i} className="mb-2 flex gap-4">
                    <span className="text-indigo-700 font-black">[{logs.length - i}]</span>
                    <span>{l}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData
} from './types';
import { 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  ShieldCheckIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  CircleStackIcon,
  FingerPrintIcon,
  SparklesIcon,
  GlobeAltIcon,
  ShieldExclamationIcon,
  BeakerIcon,
  AdjustmentsHorizontalIcon,
  ArrowTopRightOnSquareIcon,
  PlusIcon,
  ListBulletIcon,
  ArrowDownTrayIcon,
  FunnelIcon,
  MagnifyingGlassIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['Adverse drug reactions', 'Adverse Event Reporting System', 'pharmacovigilance*'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [keywordInput, setKeywordInput] = useState("");
  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  // 資料庫篩選狀態
  const [dbFilter, setDbFilter] = useState({
    ingredient: '',
    from: '',
    to: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleAddKeyword = () => {
    const trimmedKw = keywordInput.trim();
    if (trimmedKw === "") return;
    if (!input.ae_strings.includes(trimmedKw)) {
      setInput(prev => ({ ...prev, ae_strings: [...prev.ae_strings, trimmedKw] }));
      setKeywordInput("");
      addLog(`[設定] 已新增關鍵字: "${trimmedKw}"`);
    } else {
      alert("該關鍵字已存在於清單中。");
    }
  };

  const handleRemoveKeyword = (kw: string) => {
    if (input.ae_strings.length <= 1) {
      alert("至少需保留一個檢索關鍵字。");
      return;
    }
    setInput(prev => ({ ...prev, ae_strings: prev.ae_strings.filter(item => item !== kw) }));
    addLog(`[設定] 已移除關鍵字: "${kw}"`);
  };

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setSelectedRecordId(null);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const pubmedQuery = `("${ingredient}") AND (Adverse drug reactions) OR (Adverse Event Reporting System) OR (pharmacovigilance*)`;
      addLog(`[稽核] 已生成精確檢索式: ${pubmedQuery}`);

      setStep(WorkflowStep.RSS_FETCH);
      addLog(`[深度監測] 正在執行對位校驗檢索 (Pro Mode)...`);

      const realResults = await gemini.performPubMedSearch(pubmedQuery, ingredient, input.date_window);
      addLog(`[完成檢索] 找到 ${realResults.length} 筆經校驗的結果...`);

      let rawRecords: PVRecord[] = realResults.map((r: any) => ({
        id: r.pmid || `pubmed-${Math.random().toString(36).substr(2, 9)}`,
        source: 'pubmed',
        pmid: r.pmid,
        title: r.title,
        journal: r.journal,
        dp: r.date,
        abstract: r.summary,
        full_text: `[NCBI PubMed Official Record]\nPMID: ${r.pmid}\nJOURNAL: ${r.journal}\nDATE: ${r.date}\n\nSUMMARY: ${r.summary}`,
        primary_link: r.url || `https://pubmed.ncbi.nlm.nih.gov/${r.pmid}/`,
        quality_flags: ['NCBI_VERIFIED_ALIGNMENT'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false,
        pv_data: { ingredient: ingredient } as any // 記錄當時檢索的成分
      }));

      const startDate = new Date(input.date_window.from);
      const endDate = new Date(input.date_window.to);

      const filteredRecords = rawRecords.map(r => {
        const recordDate = r.dp ? new Date(r.dp) : null;
        if (!recordDate || recordDate < startDate || recordDate > endDate) {
          return { ...r, is_excluded: true, exclusion_reason: 'OUT_OF_WINDOW' };
        }
        return r;
      });

      const validRecords = filteredRecords.filter(r => !r.is_excluded);
      addLog(`[稽核完畢] 通過日期篩選文獻：${validRecords.length} 筆`);

      if (validRecords.length > 0) {
        setStep(WorkflowStep.RELEVANCE_SCORING);
        addLog(`[AI 分析] 評估 PV 相關性...`);
        const scores = await gemini.scoreRelevance(validRecords);

        setStep(WorkflowStep.SUMMARIZATION);
        addLog(`[AI 分析] 生成藥安摘要...`);
        const summaries = await gemini.generateSummaries(validRecords);

        const finalized = filteredRecords.map(m => {
          if (m.is_excluded) return m;
          const s = scores.find((sc: any) => sc.pmid === m.pmid);
          const sum = summaries.find((su: any) => su.pmid === m.pmid);
          return { 
            ...m, 
            relevance_score: s?.score || 50, 
            relevance_reason: s?.reason || '分析完成',
            summary_zh: sum?.summary_zh || m.abstract 
          };
        });
        setRecords(finalized);
      } else {
        setRecords(filteredRecords);
      }

      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (e) {
      addLog(`[錯誤] 搜尋異常: ${e instanceof Error ? e.message : '連線中斷'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    await db_upsert([record]);
    setMasterDatabase(prev => [...prev, { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] }]);
    setRecords(prev => prev.filter(r => r.id !== record.id));
    setSelectedRecordId(null);
    addLog(`[資料庫] 已匯入文獻: PMID:${record.pmid}`);
  };

  const selectedRecord = useMemo(() => 
    records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId)
  , [records, masterDatabase, selectedRecordId]);

  const [isExtracting, setIsExtracting] = useState(false);
  useEffect(() => {
    const triggerExtraction = async () => {
      if (selectedRecord && !selectedRecord.pv_data?.ae_verbatim && !isExtracting && !selectedRecord.is_excluded) {
        setIsExtracting(true);
        const data = await gemini.extractPVData(selectedRecord);
        // 保留原有的成分資訊
        const mergedData = { ...selectedRecord.pv_data, ...data };
        setRecords(prev => prev.map(r => r.id === selectedRecord.id ? { ...r, pv_data: mergedData } : r));
        setMasterDatabase(prev => prev.map(r => r.id === selectedRecord.id ? { ...r, pv_data: mergedData } : r));
        setIsExtracting(false);
      }
    };
    triggerExtraction();
  }, [selectedRecordId]);

  // 資料庫篩選邏輯
  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const matchIngredient = !dbFilter.ingredient || 
        r.pv_data?.ingredient?.toLowerCase().includes(dbFilter.ingredient.toLowerCase()) ||
        r.title?.toLowerCase().includes(dbFilter.ingredient.toLowerCase());

      const recordDate = r.dp ? new Date(r.dp) : null;
      const matchFrom = !dbFilter.from || (recordDate && recordDate >= new Date(dbFilter.from));
      const matchTo = !dbFilter.to || (recordDate && recordDate <= new Date(dbFilter.to));

      return matchIngredient && matchFrom && matchTo;
    });
  }, [masterDatabase, dbFilter]);

  // 一鍵匯出 CSV
  const exportToCSV = () => {
    if (filteredDatabase.length === 0) {
      alert("目前無資料可匯出");
      return;
    }
    const headers = ["PMID", "Title", "Journal", "Publication Date", "Ingredient", "Score", "Summary (ZH)"];
    const rows = filteredDatabase.map(r => [
      r.pmid,
      `"${r.title?.replace(/"/g, '""')}"`,
      `"${r.journal?.replace(/"/g, '""')}"`,
      r.dp,
      r.pv_data?.ingredient || "N/A",
      r.relevance_score,
      `"${r.summary_zh?.replace(/"/g, '""') || ''}"`
    ]);

    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `PV_Database_Export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    addLog(`[匯出] 已產生並下載 CSV 報表`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans">
      <div className="bg-slate-950 text-indigo-400/60 text-[10px] px-6 py-1.5 flex justify-between font-mono tracking-widest border-b border-slate-800">
        <span>NCBI-PRO-VERIFIED // ALIGNMENT-LOCKED</span>
        <span>SYSTEM_TIME: {now().iso_datetime}</span>
      </div>

      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center sticky top-0 z-30 shadow-sm">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-xl shadow-indigo-200">
            <BeakerIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">PV-Link <span className="text-indigo-600">PubMed Auditor</span></h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">
              <GlobeAltIcon className="w-3 h-3" /> 專業數據稽核模式 (Pro)
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {isProcessing && (
             <div className="text-xs font-black text-indigo-600 animate-pulse bg-indigo-50 px-4 py-2 rounded-full border border-indigo-100 flex items-center gap-2">
               <ArrowPathIcon className="w-3 h-3 animate-spin" /> {step}
             </div>
          )}
          <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-6 py-3 rounded-2xl text-sm font-black shadow-lg shadow-indigo-100 flex items-center gap-2 transition-all active:scale-95">
            <ArrowPathIcon className={`w-5 h-5 ${isProcessing ? 'animate-spin' : ''}`} />
            啟動監測任務
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col p-6 space-y-2">
          <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <AdjustmentsHorizontalIcon className="w-5 h-5" /> 任務參數
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
