import React, { useState, useMemo, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData
} from './types';
import { 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  CheckCircleIcon,
  ShieldCheckIcon,
  DocumentMagnifyingGlassIcon,
  QueueListIcon,
  XMarkIcon,
  CircleStackIcon,
  FingerPrintIcon,
  SparklesIcon,
  GlobeAltIcon,
  ShieldExclamationIcon,
  BeakerIcon,
  AdjustmentsHorizontalIcon,
  ArrowTopRightOnSquareIcon,
  PlusIcon,
  ListBulletIcon,
  ArrowDownTrayIcon,
  FunnelIcon,
  MagnifyingGlassIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['Adverse drug reactions', 'Adverse Event Reporting System', 'pharmacovigilance*'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [keywordInput, setKeywordInput] = useState("");
  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  // 資料庫篩選狀態
  const [dbFilter, setDbFilter] = useState({
    keyword: '',
    from: '',
    to: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleAddKeyword = () => {
    const trimmedKw = keywordInput.trim();
    if (trimmedKw === "") return;
    if (!input.ae_strings.includes(trimmedKw)) {
      setInput(prev => ({ ...prev, ae_strings: [...prev.ae_strings, trimmedKw] }));
      setKeywordInput("");
      addLog(`[設定] 已新增關鍵字: "${trimmedKw}"`);
    } else {
      alert("該關鍵字已存在於清單中。");
    }
  };

  const handleRemoveKeyword = (kw: string) => {
    if (input.ae_strings.length <= 1) {
      alert("至少需保留一個檢索關鍵字。");
      return;
    }
    setInput(prev => ({ ...prev, ae_strings: prev.ae_strings.filter(item => item !== kw) }));
    addLog(`[設定] 已移除關鍵字: "${kw}"`);
  };

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    setSelectedRecordId(null);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const pubmedQuery = `("${ingredient}") AND (Adverse drug reactions) OR (Adverse Event Reporting System) OR (pharmacovigilance*)`;
      addLog(`[稽核] 已生成精確檢索式: ${pubmedQuery}`);

      setStep(WorkflowStep.RSS_FETCH);
      addLog(`[深度監測] 正在執行對位校驗檢索 (Pro Mode)...`);

      const realResults = await gemini.performPubMedSearch(pubmedQuery, ingredient, input.date_window);
      addLog(`[完成檢索] 找到 ${realResults.length} 筆經校驗的結果...`);

      let rawRecords: PVRecord[] = realResults.map((r: any) => ({
        id: r.pmid || `pubmed-${Math.random().toString(36).substr(2, 9)}`,
        source: 'pubmed',
        pmid: r.pmid,
        title: r.title,
        journal: r.journal,
        dp: r.date,
        abstract: r.summary,
        full_text: `[NCBI PubMed Official Record]\nPMID: ${r.pmid}\nJOURNAL: ${r.journal}\nDATE: ${r.date}\n\nSUMMARY: ${r.summary}`,
        primary_link: r.url || `https://pubmed.ncbi.nlm.nih.gov/${r.pmid}/`,
        quality_flags: ['NCBI_VERIFIED_ALIGNMENT'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false,
        pv_data: { ingredient: ingredient } as any // 初始記錄檢索成分
      }));

      const startDate = new Date(input.date_window.from);
      const endDate = new Date(input.date_window.to);

      const filteredRecords = rawRecords.map(r => {
        const recordDate = r.dp ? new Date(r.dp) : null;
        if (!recordDate || recordDate < startDate || recordDate > endDate) {
          return { ...r, is_excluded: true, exclusion_reason: 'OUT_OF_WINDOW' };
        }
        return r;
      });

      const validRecords = filteredRecords.filter(r => !r.is_excluded);
      addLog(`[稽核完畢] 通過日期篩選文獻：${validRecords.length} 筆`);

      if (validRecords.length > 0) {
        setStep(WorkflowStep.RELEVANCE_SCORING);
        const scores = await gemini.scoreRelevance(validRecords);
        setStep(WorkflowStep.SUMMARIZATION);
        const summaries = await gemini.generateSummaries(validRecords);

        const finalized = filteredRecords.map(m => {
          if (m.is_excluded) return m;
          const s = scores.find((sc: any) => sc.pmid === m.pmid);
          const sum = summaries.find((su: any) => su.pmid === m.pmid);
          return { 
            ...m, 
            relevance_score: s?.score || 50, 
            relevance_reason: s?.reason || '分析完成',
            summary_zh: sum?.summary_zh || m.abstract 
          };
        });
        setRecords(finalized);
      } else {
        setRecords(filteredRecords);
      }

      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (e) {
      addLog(`[錯誤] 搜尋異常: ${e instanceof Error ? e.message : '連線中斷'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    // 在匯入前，確保 pv_data 中包含了檢索時的成分資訊，防止被 AI 提取結果完全覆蓋
    const preparedRecord = {
      ...record,
      quality_flags: [...record.quality_flags, 'DB_COMMITTED']
    };
    await db_upsert([preparedRecord]);
    setMasterDatabase(prev => [...prev, preparedRecord]);
    setRecords(prev => prev.filter(r => r.id !== record.id));
    setSelectedRecordId(null);
    addLog(`[資料庫] 已匯入文獻: PMID:${record.pmid}`);
  };

  const selectedRecord = useMemo(() => 
    records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId)
  , [records, masterDatabase, selectedRecordId]);

  const [isExtracting, setIsExtracting] = useState(false);
  useEffect(() => {
    const triggerExtraction = async () => {
      // 只有當選中的紀錄沒有詳細 PV 數據時才提取
      if (selectedRecord && !selectedRecord.pv_data?.ae_verbatim && !isExtracting && !selectedRecord.is_excluded) {
        setIsExtracting(true);
        const data = await gemini.extractPVData(selectedRecord);

        // 關鍵修正：採用合併模式。如果 AI 沒提取到 ingredient，保留原本的 ingredient
        const updateFn = (r: PVRecord) => {
          if (r.id !== selectedRecord.id) return r;
          const originalIngredient = r.pv_data?.ingredient;
          return { 
            ...r, 
            pv_data: { 
              ...data, 
              // 如果 AI 提取的成分無效，則使用原始檢索成分
              ingredient: data.ingredient && data.ingredient !== 'N/A' ? data.ingredient : originalIngredient 
            } 
          };
        };

        setRecords(prev => prev.map(updateFn));
        setMasterDatabase(prev => prev.map(updateFn));
        setIsExtracting(false);
      }
    };
    triggerExtraction();
  }, [selectedRecordId]);

  // 資料庫篩選邏輯 (強化模糊搜尋)
  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const kw = dbFilter.keyword.toLowerCase();
      // 1. 模糊成分與標題匹配
      const matchKeyword = !dbFilter.keyword || 
        r.pv_data?.ingredient?.toLowerCase().includes(kw) ||
        r.title?.toLowerCase().includes(kw) ||
        r.pmid?.toLowerCase().includes(kw) ||
        r.journal?.toLowerCase().includes(kw);

      // 2. 日期匹配
      const recordDate = r.dp ? new Date(r.dp) : null;
      const matchFrom = !dbFilter.from || (recordDate && recordDate >= new Date(dbFilter.from));
      const matchTo = !dbFilter.to || (recordDate && recordDate <= new Date(dbFilter.to));

      return matchKeyword && matchFrom && matchTo;
    });
  }, [masterDatabase, dbFilter]);

  const exportToCSV = () => {
    if (filteredDatabase.length === 0) {
      alert("目前無資料可匯出");
      return;
    }
    const headers = ["PMID", "Title", "Journal", "Publication Date", "Ingredient", "Score", "Summary (ZH)"];
    const rows = filteredDatabase.map(r => [
      r.pmid,
      `"${r.title?.replace(/"/g, '""')}"`,
      `"${r.journal?.replace(/"/g, '""')}"`,
      r.dp,
      r.pv_data?.ingredient || "N/A",
      r.relevance_score,
      `"${r.summary_zh?.replace(/"/g, '""') || ''}"`
    ]);

    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `PV_Database_Export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans">
      <div className="bg-slate-950 text-indigo-400/60 text-[10px] px-6 py-1.5 flex justify-between font-mono tracking-widest border-b border-slate-800">
        <span>NCBI-PRO-VERIFIED // DB-CONSISTENCY-LOCKED</span>
        <span>SYSTEM_TIME: {now().iso_datetime}</span>
      </div>

      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center sticky top-0 z-30 shadow-sm">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-xl shadow-indigo-200">
            <BeakerIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">PV-Link <span className="text-indigo-600">PubMed Auditor</span></h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">
              <GlobeAltIcon className="w-3 h-3" /> 專業數據稽核模式 (Pro)
            </p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {isProcessing && (
             <div className="text-xs font-black text-indigo-600 animate-pulse bg-indigo-50 px-4 py-2 rounded-full border border-indigo-100 flex items-center gap-2">
               <ArrowPathIcon className="w-3 h-3 animate-spin" /> {step}
             </div>
          )}
          <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-6 py-3 rounded-2xl text-sm font-black shadow-lg shadow-indigo-100 flex items-center gap-2 transition-all active:scale-95">
            <ArrowPathIcon className={`w-5 h-5 ${isProcessing ? 'animate-spin' : ''}`} />
            啟動監測任務
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col p-6 space-y-2">
          <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <AdjustmentsHorizontalIcon className="w-5 h-5" /> 任務參數
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 核閱清單 ({records.filter(r => !r.is_excluded).length})
          </button>
          <button onClick={() => setActiveTab('database')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'database' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <CircleStackIcon className="w-5 h-5" /> 正式資料庫 ({masterDatabase.length})
          </button>
          <div className="mt-auto pt-4 border-t border-slate-100 text-center">
            <button onClick={() => setActiveTab('logs')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[10px] font-black transition-all text-slate-400 hover:text-slate-600 uppercase tracking-widest`}>
              <FingerPrintIcon className="w-4 h-4" /> 稽核日誌
            </button>
          </div>
        </aside>

        <section className="flex-1 overflow-hidden flex flex-col">
          {activeTab === 'input' && (
            <div className="flex-1 overflow-y-auto p-12 bg-slate-50/50">
              <div className="max-w-2xl mx-auto space-y-12">
                <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl space-y-10">
                   <div className="flex items-center gap-3">
                     <div className="bg-indigo-100 p-2 rounded-xl text-indigo-600"><BeakerIcon className="w-6 h-6" /></div>
                     <h2 className="text-3xl font-black text-slate-900 tracking-tight">PubMed 檢索配置</h2>
                   </div>
                  <div className="space-y-6">
                    <div className="group">
                      <label className="text-[10px] font-black text-slate-400 uppercase mb-3 block tracking-widest">鎖定主成分 (API)</label>
                      <input type="text" value={input.active_ingredients[0]} onChange={e => setInput({...input, active_ingredients: [e.target.value]})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-[1.5rem] px-6 py-5 text-xl font-black outline-none focus:border-indigo-600 focus:bg-white transition-all shadow-sm" placeholder="例如: Fenofibrate" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 mb-2 block uppercase tracking-widest">日期起始</label>
                        <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-5 py-4 font-black outline-none focus:border-indigo-600" />
                      </div>
                      <div>
                        <label className="text-[10px] font-black text-slate-400 mb-2 block uppercase tracking-widest">日期結束</label>
                        <input type="date" value={input.date_window.to} onChange={e => setInput({...input, date_window: {...input.date_window, to: e.target.value}})} className="w-full bg-slate-50 border-slate-200 border-2 rounded-2xl px-5 py-4 font-black outline-none focus:border-indigo-600" />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'review' && (
            <div className="flex-1 flex overflow-hidden">
              <div className="w-[45%] overflow-y-auto p-8 space-y-4 border-r border-slate-200 bg-slate-50/50">
                <div className="flex justify-between items-end mb-4">
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">文獻獲取結果</h2>
                  <span className="text-[10px] font-black text-slate-400 bg-white px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">{records.length} Records</span>
                </div>
                {records.map(r => (
                  <div key={r.id} onClick={() => setSelectedRecordId(r.id)} className={`group p-6 rounded-[2rem] border-2 cursor-pointer transition-all ${selectedRecordId === r.id ? 'border-indigo-600 bg-white ring-8 ring-indigo-50 shadow-xl' : r.is_excluded ? 'border-slate-100 bg-slate-100/50 opacity-60 grayscale' : 'border-white bg-white hover:border-slate-200 shadow-sm'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-2">
                        {r.is_excluded ? (
                           <span className="text-[8px] px-2 py-0.5 rounded-full font-black uppercase tracking-widest bg-red-50 text-red-600 border border-red-100">Out of Date</span>
                        ) : (
                           <span className="text-[8px] px-2 py-0.5 rounded-full font-black uppercase tracking-widest bg-emerald-50 text-emerald-600 border border-emerald-100">In Window</span>
                        )}
                        <span className="text-[10px] font-mono font-bold text-slate-400">{r.dp}</span>
                      </div>
                      <span className="text-[8px] px-2 py-0.5 rounded-full font-black tracking-widest bg-slate-100 text-slate-500">PMID:{r.pmid}</span>
                    </div>
                    <h3 className="font-black text-slate-800 leading-snug text-sm mb-2 group-hover:text-indigo-600 transition-colors line-clamp-2">{r.title}</h3>
                    <p className="text-[10px] font-bold text-slate-400 truncate italic">{r.journal}</p>
                  </div>
                ))}
              </div>

              <div className="flex-1 bg-white overflow-y-auto p-12">
                {selectedRecord ? (
                  <div className="max-w-xl mx-auto space-y-10">
                    <div className="space-y-4">
                      <h2 className="text-2xl font-black text-slate-900 leading-tight">{selectedRecord.title}</h2>
                      <button onClick={() => window.open(selectedRecord.primary_link, '_blank')} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[11px] hover:bg-slate-800 transition-all shadow-lg active:scale-95">
                        <ArrowTopRightOnSquareIcon className="w-4 h-4" /> 驗證原始連結 (PMID:{selectedRecord.pmid})
                      </button>
                    </div>

                    {!selectedRecord.is_excluded && (
                      <>
                        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 text-white rounded-[2.5rem] p-10 shadow-2xl">
                          <div className="text-[10px] font-black text-indigo-200 uppercase mb-4 tracking-widest">AI 摘要</div>
                          <p className="text-lg font-bold leading-relaxed">{selectedRecord.summary_zh || "分析中..."}</p>
                        </div>
                        <button onClick={() => handleImport(selectedRecord)} className="w-full bg-emerald-600 text-white py-6 rounded-[2rem] font-black hover:bg-emerald-700 shadow-xl text-xl transition-all">
                          匯入正式資料庫
                        </button>
                      </>
                    )}
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-slate-200">
                    <DocumentMagnifyingGlassIcon className="w-20 h-20 opacity-10" />
                    <p className="font-black uppercase tracking-widest mt-4">請選擇一筆紀錄</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'database' && (
            <div className="w-full h-full bg-slate-50 p-12 overflow-hidden flex flex-col">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">正式文獻庫</h2>
                  <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-2">Validated PV Knowledge Base</p>
                </div>
                <button onClick={exportToCSV} className="bg-emerald-100 text-emerald-700 px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-2 hover:bg-emerald-200 transition-all shadow-md">
                  <ArrowDownTrayIcon className="w-5 h-5" /> 匯出 CSV
                </button>
              </div>

              {/* 篩選器列 */}
              <div className="bg-white p-6 rounded-[2rem] border border-slate-200 mb-6 flex flex-wrap gap-4 items-end shadow-sm">
                <div className="flex-1 min-w-[200px]">
                  <label className="text-[9px] font-black text-slate-400 uppercase mb-2 block tracking-widest">模糊搜尋 (PMID/標題/成分/期刊)</label>
                  <div className="relative">
                    <MagnifyingGlassIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                    <input 
                      type="text" 
                      placeholder="輸入關鍵字..."
                      value={dbFilter.keyword}
                      onChange={e => setDbFilter({...dbFilter, keyword: e.target.value})}
                      className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl pl-12 pr-4 py-2.5 text-xs font-black outline-none focus:border-indigo-600 transition-all"
                    />
                  </div>
                </div>
                <div>
                  <label className="text-[9px] font-black text-slate-400 uppercase mb-2 block tracking-widest">日期範圍</label>
                  <div className="flex items-center gap-2">
                    <input type="date" value={dbFilter.from} onChange={e => setDbFilter({...dbFilter, from: e.target.value})} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-xs font-black outline-none" />
                    <span className="text-slate-300 font-bold">~</span>
                    <input type="date" value={dbFilter.to} onChange={e => setDbFilter({...dbFilter, to: e.target.value})} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-xs font-black outline-none" />
                  </div>
                </div>
                <button onClick={() => setDbFilter({ keyword: '', from: '', to: '' })} className="text-slate-400 hover:text-indigo-600 px-4 py-2 text-[10px] font-black uppercase tracking-widest">重設</button>
              </div>

              <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl flex-1 overflow-auto">
                <table className="w-full">
                  <thead className="bg-slate-50 sticky top-0 border-b border-slate-100 z-10">
                    <tr>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">PMID</th>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">文獻標題 / 成分</th>
                      <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">期刊與出版日期</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredDatabase.length === 0 ? (
                      <tr>
                        <td colSpan={3} className="px-8 py-20 text-center text-slate-300 font-black uppercase tracking-widest text-sm">
                          未發現符合條件的文獻 (目前總數: {masterDatabase.length})
                        </td>
                      </tr>
                    ) : filteredDatabase.map(r => (
                      <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => { setSelectedRecordId(r.id); setActiveTab('review'); }}>
                        <td className="px-8 py-8 font-mono text-[11px] text-slate-500 font-bold">{r.pmid}</td>
                        <td className="px-8 py-8">
                          <div className="font-black text-slate-800 leading-snug line-clamp-2">{r.title}</div>
                          <div className="flex gap-2 mt-2">
                             <span className="bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-tighter">
                               {r.pv_data?.ingredient || "成分未標註"}
                             </span>
                          </div>
                        </td>
                        <td className="px-8 py-8">
                          <div className="font-bold text-slate-400 text-xs italic">{r.journal}</div>
                          <div className="text-[10px] font-mono text-indigo-400 mt-1 font-black">{r.dp}</div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="flex-1 p-12 overflow-y-auto font-mono text-xs text-slate-400 space-y-2">
              {logs.map((l, i) => <div key={i}>{l}</div>)}
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

export default App;

export interface PVInput {
  company_product_names: string[];
  active_ingredients: string[];
  date_window: { from: string; to: string };
  date_logic: 'dp' | 'edat' | 'both';
  ae_strings: string[];
  optional_ae_focus_terms: string[];
  exclusions: string[];
  db_mode: 'insert-only' | 'upsert';
}

export interface PVRecord {
  id: string;
  source: 'pubmed' | 'web';
  pmid?: string;
  doi?: string;
  title: string;
  authors?: string[];
  journal?: string;
  year?: string;
  dp?: string;
  edat?: string;
  abstract?: string;
  full_text?: string;
  primary_link: string;
  pubmed_url?: string;
  journal_url?: string;
  quality_flags: string[];
  relevance_score: number;
  relevance_reason: string;
  summary_zh?: string;
  is_excluded: boolean;
  exclusion_reason?: string;
  pv_data?: PVStructuredData;
  original_search_term?: string; // 新增：保存原始檢索時的成分關鍵字
  cimos_draft?: any;
}

export interface PVStructuredData {
  product: string;
  ingredient: string;
  ae_verbatim: string;
  meddra_pt_candidate: string;
  meddra_confidence: number;
  seriousness: string;
  population: string;
  dosage_route: string;
  tto: string;
  outcome: string;
  causality: string;
  completeness: 'Complete' | 'Partial' | 'Missing';
}

export enum WorkflowStep {
  IDLE = "閒置",
  QUERY_GEN = "查詢式生成",
  RSS_FETCH = "RSS 獲取",
  EFETCH_FILTER = "嚴格篩選與去重",
  WEB_SEARCH = "網路來源補強",
  RELEVANCE_SCORING = "PV 相關性評分",
  SUMMARIZATION = "繁中摘要生成",
  PV_EXTRACTION = "結構化抽取",
  DB_EXPORT = "資料庫匯入"
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData
} from './types';
import { 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  DocumentMagnifyingGlassIcon,
  XMarkIcon,
  CircleStackIcon,
  FingerPrintIcon,
  SparklesIcon,
  GlobeAltIcon,
  BeakerIcon,
  AdjustmentsHorizontalIcon,
  ArrowTopRightOnSquareIcon,
  ArrowDownTrayIcon,
  FunnelIcon,
  MagnifyingGlassIcon,
  InboxIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();
const DB_STORAGE_KEY = 'PV_AUDITOR_MASTER_DB';

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['Adverse drug reactions', 'Adverse Event Reporting System', 'pharmacovigilance*'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>(() => {
    const saved = localStorage.getItem(DB_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  const [dbFilter, setDbFilter] = useState({
    keyword: '',
    from: '',
    to: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  // 持久化儲存
  useEffect(() => {
    localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(masterDatabase));
  }, [masterDatabase]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const pubmedQuery = `("${ingredient}") AND (Adverse drug reactions) OR (Adverse Event Reporting System) OR (pharmacovigilance*)`;
      addLog(`[稽核] 啟動監測任務，成分：${ingredient}`);

      setStep(WorkflowStep.RSS_FETCH);
      const realResults = await gemini.performPubMedSearch(pubmedQuery, ingredient, input.date_window);

      const rawRecords: PVRecord[] = realResults.map((r: any) => ({
        id: r.pmid || `tmp-${Math.random()}`,
        source: 'pubmed',
        pmid: r.pmid,
        title: r.title,
        journal: r.journal,
        dp: r.date,
        abstract: r.summary,
        primary_link: r.url,
        quality_flags: ['PRO_VERIFIED'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false,
        original_search_term: ingredient // 關鍵優化：鎖定原始搜尋詞
      }));

      // 檢查是否已在資料庫中
      const freshRecords = rawRecords.filter(r => !masterDatabase.some(m => m.pmid === r.pmid));
      addLog(`[完成檢索] 找到 ${rawRecords.length} 筆，排除已存在筆數後剩餘 ${freshRecords.length} 筆新資料`);

      if (freshRecords.length > 0) {
        setStep(WorkflowStep.RELEVANCE_SCORING);
        const scores = await gemini.scoreRelevance(freshRecords);
        setStep(WorkflowStep.SUMMARIZATION);
        const summaries = await gemini.generateSummaries(freshRecords);

        const finalized = freshRecords.map(m => {
          const s = scores.find((sc: any) => sc.pmid === m.pmid);
          const sum = summaries.find((su: any) => su.pmid === m.pmid);
          return { 
            ...m, 
            relevance_score: s?.score || 50, 
            relevance_reason: s?.reason || '分析完成',
            summary_zh: sum?.summary_zh || m.abstract 
          };
        });
        setRecords(finalized);
      } else {
        setRecords([]);
        addLog(`[提示] 本次搜尋無新文獻需要核閱。`);
      }

      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (e) {
      addLog(`[錯誤] 執行異常: ${e instanceof Error ? e.message : 'Unknown'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    if (masterDatabase.some(m => m.pmid === record.pmid)) {
      alert("此文獻 (PMID: " + record.pmid + ") 已存在於資料庫中。");
      return;
    }
    const preparedRecord = { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] };
    setMasterDatabase(prev => [...prev, preparedRecord]);
    setRecords(prev => prev.filter(r => r.pmid !== record.pmid));
    setSelectedRecordId(null);
    addLog(`[資料庫] 成功匯入文獻 PMID:${record.pmid}`);
  };

  const selectedRecord = useMemo(() => 
    records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId)
  , [records, masterDatabase, selectedRecordId]);

  const [isExtracting, setIsExtracting] = useState(false);
  useEffect(() => {
    const triggerExtraction = async () => {
      if (selectedRecord && !selectedRecord.pv_data?.ae_verbatim && !isExtracting && !selectedRecord.is_excluded) {
        setIsExtracting(true);
        const data = await gemini.extractPVData(selectedRecord);
        const updateFn = (r: PVRecord) => {
          if (r.id !== selectedRecord.id) return r;
          return { 
            ...r, 
            pv_data: { 
              ...data,
              // 如果 AI 沒抽到成分，絕不覆蓋原始成分
              ingredient: data.ingredient && data.ingredient !== 'N/A' ? data.ingredient : r.original_search_term 
            } 
          };
        };
        setRecords(prev => prev.map(updateFn));
        setMasterDatabase(prev => prev.map(updateFn));
        setIsExtracting(false);
      }
    };
    triggerExtraction();
  }, [selectedRecordId]);

  // 超強模糊檢索邏輯
  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const kw = dbFilter.keyword.toLowerCase();
      // 多重欄位匹配
      const contentPool = [
        r.pmid || '',
        r.title || '',
        r.original_search_term || '',
        r.pv_data?.ingredient || '',
        r.pv_data?.product || '',
        r.journal || '',
        r.summary_zh || ''
      ].join(' ').toLowerCase();

      const matchKeyword = !dbFilter.keyword || contentPool.includes(kw);
      const recordDate = r.dp ? new Date(r.dp) : null;
      const matchFrom = !dbFilter.from || (recordDate && recordDate >= new Date(dbFilter.from));
      const matchTo = !dbFilter.to || (recordDate && recordDate <= new Date(dbFilter.to));

      return matchKeyword && matchFrom && matchTo;
    });
  }, [masterDatabase, dbFilter]);

  const exportToCSV = () => {
    const headers = ["PMID", "Title", "Journal", "PubDate", "SearchTerm", "AI_Ingredient", "Score"];
    const rows = filteredDatabase.map(r => [
      r.pmid, `"${r.title}"`, `"${r.journal}"`, r.dp, r.original_search_term, r.pv_data?.ingredient, r.relevance_score
    ]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `PV_DB_Export_${now().iso_datetime.split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans">
      <div className="bg-slate-950 text-indigo-400/60 text-[10px] px-6 py-1.5 flex justify-between font-mono tracking-widest border-b border-slate-800">
        <span>PV-AUDITOR // DATA-INTEGRITY-ENABLED</span>
        <span>SYSTEM_TIME: {now().iso_datetime}</span>
      </div>

      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center sticky top-0 z-30 shadow-sm">
        <div className="flex items-center gap-5">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg"><BeakerIcon className="w-7 h-7" /></div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">PV-Link Auditor</h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">專業稽核模式 (PRO-V3)</p>
          </div>
        </div>
        <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-3 rounded-2xl text-sm font-black shadow-lg flex items-center gap-3 transition-all">
          <ArrowPathIcon className={`w-5 h-5 ${isProcessing ? 'animate-spin' : ''}`} />
          {isProcessing ? step : '啟動新監測任務'}
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col p-6 space-y-2">
          <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <AdjustmentsHorizontalIcon className="w-5 h-5" /> 檢索設定
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 待核閱 ({records.length})
          </button>
          <button onClick={() => setActiveTab('database')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'database' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <CircleStackIcon className="w-5 h-5" /> 正式庫 ({masterDatabase.length})
          </button>
          <button onClick={() => setActiveTab('logs')} className="mt-auto w-full flex items-center gap-4 px-5 py-4 text-[10px] font-black uppercase text-slate-400">
            <FingerPrintIcon className="w-4 h-4" /> 系統日誌
          </button>
        </aside>

        <section className="flex-1 overflow-hidden flex flex-col">
          {activeTab === 'input' && (
            <div className="flex-1 p-20 flex flex-col items-center">
               <div className="w-full max-w-xl bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl space-y-10">
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">藥物監測配置</h2>
                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">目標成分 (必填)</label>
                       <input type="text" value={input.active_ingredients[0]} onChange={e => setInput({...input, active_ingredients: [e.target.value]})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 text-lg font-black outline-none focus:border-indigo-600 transition-all" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                       <div className="space-y-2">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">監測起始</label>
                         <input type="date" value={input.date_window.from} onChange={e => setInput({...input, date_window: {...input.date_window, from: e.target.value}})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-black text-sm" />
                       </div>
                       <div className="space-y-2">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">監測結束</label>
                         <input type="date" value={input.date_window.to} onChange={e => setInput({...input, date_window: {...input.date_window, to: e.target.value}})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-black text-sm" />
                       </div>
                    </div>
                  </div>
               </div>
            </div>
          )}

          {activeTab === 'review' && (
             <div className="flex-1 flex">
               <div className="w-[45%] border-r border-slate-100 overflow-y-auto p-8 space-y-4 bg-slate-50/50">
                  {records.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center opacity-20"><InboxIcon className="w-16 h-16" /><p className="font-black mt-4">無待核閱文獻</p></div>
                  ) : records.map(r => (
                    <div key={r.id} onClick={() => setSelectedRecordId(r.id)} className={`p-6 rounded-[2rem] border-2 cursor-pointer transition-all ${selectedRecordId === r.id ? 'border-indigo-600 bg-white shadow-xl' : 'border-white bg-white hover:border-slate-200'}`}>
                       <div className="flex justify-between items-start mb-2">
                         <span className="text-[10px] font-black text-indigo-400">{r.dp}</span>
                         <span className="text-[10px] font-black text-slate-300">PMID:{r.pmid}</span>
                       </div>
                       <h3 className="font-black text-slate-800 text-sm leading-tight line-clamp-2">{r.title}</h3>
                    </div>
                  ))}
               </div>
               <div className="flex-1 bg-white p-12 overflow-y-auto">
                 {selectedRecord ? (
                   <div className="max-w-xl mx-auto space-y-10">
                      <div className="space-y-4">
                        <div className="flex items-center gap-2 text-indigo-600 text-[10px] font-black tracking-widest uppercase"><SparklesIcon className="w-4 h-4" /> 文獻稽核詳情</div>
                        <h2 className="text-2xl font-black text-slate-900">{selectedRecord.title}</h2>
                        <button onClick={() => window.open(selectedRecord.primary_link, '_blank')} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[11px] shadow-lg">
                          <ArrowTopRightOnSquareIcon className="w-4 h-4" /> 官網驗證連結
                        </button>
                      </div>
                      <div className="bg-indigo-900 text-white p-10 rounded-[2.5rem] shadow-2xl">
                         <div className="text-[10px] font-black text-indigo-300 mb-4 tracking-widest uppercase">AI 藥安摘要</div>
                         <p className="text-lg font-bold leading-relaxed">{selectedRecord.summary_zh || "正在解析中..."}</p>
                      </div>
                      {!masterDatabase.some(m => m.pmid === selectedRecord.pmid) && (
                        <button onClick={() => handleImport(selectedRecord)} className="w-full bg-emerald-600 text-white py-6 rounded-[2rem] font-black text-xl shadow-xl active:scale-95 transition-all">
                          確認匯入正式庫
                        </button>
                      )}
                   </div>
                 ) : (
                   <div className="h-full flex flex-col items-center justify-center opacity-10"><DocumentMagnifyingGlassIcon className="w-20 h-20" /></div>
                 )}
               </div>
             </div>
          )}

          {activeTab === 'database' && (
            <div className="w-full h-full bg-slate-50 p-12 flex flex-col overflow-hidden">
               <div className="flex justify-between items-start mb-8">
                  <div>
                    <h2 className="text-4xl font-black text-slate-900">正式文獻庫</h2>
                    <p className="text-slate-400 text-xs font-black uppercase mt-1">總筆數: {masterDatabase.length} | 篩選後: {filteredDatabase.length}</p>
                  </div>
                  <button onClick={exportToCSV} className="bg-emerald-100 text-emerald-700 px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-2 hover:bg-emerald-200 transition-all">
                    <ArrowDownTrayIcon className="w-5 h-5" /> 匯出 CSV 報表
                  </button>
               </div>

               <div className="bg-white p-6 rounded-[2rem] border border-slate-200 mb-6 flex flex-wrap gap-4 items-end">
                  <div className="flex-1 min-w-[300px] relative">
                    <MagnifyingGlassIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                    <input type="text" placeholder="全域檢索: PMID、標題、成分或摘要關鍵字..." value={dbFilter.keyword} onChange={e => setDbFilter({...dbFilter, keyword: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl pl-12 pr-4 py-3 text-sm font-black outline-none focus:border-indigo-600 transition-all" />
                  </div>
                  <div className="flex items-center gap-3">
                    <FunnelIcon className="w-5 h-5 text-slate-300" />
                    <input type="date" value={dbFilter.from} onChange={e => setDbFilter({...dbFilter, from: e.target.value})} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-xs font-black" />
                    <span className="text-slate-300">~</span>
                    <input type="date" value={dbFilter.to} onChange={e => setDbFilter({...dbFilter, to: e.target.value})} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-xs font-black" />
                  </div>
                  <button onClick={() => setDbFilter({ keyword: '', from: '', to: '' })} className="text-slate-400 hover:text-indigo-600 font-black text-[10px] uppercase p-2">清空</button>
               </div>

               <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-xl flex-1 overflow-auto">
                 <table className="w-full">
                   <thead className="bg-slate-50 sticky top-0 z-10">
                     <tr className="border-b border-slate-100">
                       <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">文獻 ID</th>
                       <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">文獻細節</th>
                       <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase text-left">出版資訊</th>
                     </tr>
                   </thead>
                   <tbody>
                     {filteredDatabase.length === 0 ? (
                       <tr><td colSpan={3} className="py-20 text-center text-slate-300 font-black italic">查無資料</td></tr>
                     ) : filteredDatabase.map(r => (
                       <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50 cursor-pointer" onClick={() => { setSelectedRecordId(r.id); setActiveTab('review'); }}>
                         <td className="px-8 py-8 font-mono text-xs font-bold text-slate-400">{r.pmid}</td>
                         <td className="px-8 py-8 max-w-lg">
                           <div className="font-black text-slate-800 line-clamp-2">{r.title}</div>
                           <div className="flex gap-2 mt-2">
                             <span className="bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded text-[8px] font-black uppercase">標籤: {r.original_search_term}</span>
                             {r.pv_data?.ingredient && r.pv_data.ingredient !== r.original_search_term && (
                               <span className="bg-amber-50 text-amber-600 px-2 py-0.5 rounded text-[8px] font-black uppercase">AI 識別: {r.pv_data.ingredient}</span>
                             )}
                           </div>
                         </td>
                         <td className="px-8 py-8">
                           <div className="font-bold text-slate-400 text-xs italic">{r.journal}</div>
                           <div className="text-[10px] font-mono text-indigo-400 font-black mt-1">{r.dp}</div>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="flex-1 p-12 bg-slate-950 font-mono text-[11px] text-indigo-300/80 overflow-y-auto">
               {logs.map((l, i) => <div key={i} className="mb-1">{l}</div>)}
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

export default App;

