export enum WorkflowStep {
  IDLE = "閒置",
  QUERY_GEN = "查詢式生成",
  RSS_FETCH = "RSS 獲取",
  EFETCH_FILTER = "嚴格篩選與去重",
  WEB_SEARCH = "網路來源補強",
  RELEVANCE_SCORING = "PV 相關性評分",
  SUMMARIZATION = "繁中摘要生成",
  PV_EXTRACTION = "結構化抽取",
  DB_EXPORT = "資料庫匯入"
}

import { GoogleGenAI, Type } from "@google/genai";

export class PVGeminiService {
  private get ai() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * 使用 Pro 模型進行搜尋，並實施嚴格的資料對位稽核。
   */
  async performPubMedSearch(query: string, ingredient: string, dateWindow: { from: string, to: string }) {
    try {
      // 搜尋任務改用 Pro 模型，以獲得最高精度的資料對位能力
      const response = await this.ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: `你是一個「法庭級」藥品安全監視 (PV) 數據稽核員。你的生命指標是「標題與網址必須絕對正確對應」。

        任務：
        在 NCBI PubMed 上搜尋關於「${ingredient}」的文獻。
        使用的精確查詢式：${query}
        監測時間：${dateWindow.from} ~ ${dateWindow.to}

        【關鍵對位規範 - 違反將導致系統崩潰】：
        1. 標題與連結必須 1:1 鎖定：你必須檢查 googleSearch 提供的每一個結果。JSON 中的 "title" 必須是該 "url" 網頁真正的標題。嚴禁將搜尋結果 A 的標題配上搜尋結果 B 的連結。
        2. PMID 提取限制："pmid" 必須直接從該筆結果的 "url" 字串末端提取數字（例如 https://pubmed.ncbi.nlm.nih.gov/38800001/ 的 PMID 就是 38800001）。絕對禁止自行猜測或編造 PMID。
        3. 真實性檢查：如果搜尋結果中出現了像 PMID 41257401 或 39439603 這種編號，你必須確認該網址內的論文標題真的與 ${ingredient} 有關。如果該網址是關於「呼吸運動」或「生育能力」等無關內容，請直接捨棄，不要強行填入藥品標題。
        4. 排除無關結果：僅保留來自 pubmed.ncbi.nlm.nih.gov 且內容確實涉及 ${ingredient} 的結果。

        回傳格式 (必須為純 JSON 陣列)：
        [
          {
            "pmid": "從該筆正確連結末端提取的數字",
            "title": "該連結網頁對應的真實標題",
            "date": "YYYY-MM-DD",
            "journal": "該連結網頁顯示的期刊名稱",
            "summary": "該連結網頁的真實摘要片段",
            "url": "https://pubmed.ncbi.nlm.nih.gov/PMID數字/"
          }
        ]`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        },
      });

      const text = response.text.trim();
      const results = JSON.parse(text || '[]');

      // 最後一道程式過濾：確保 URL 跟 PMID 是連動的
      return results.filter((r: any) => 
        r.url && 
        r.url.includes(r.pmid) && 
        r.url.includes('pubmed.ncbi.nlm.nih.gov')
      );
    } catch (e) {
      console.error("Critical Search Precision Error:", e);
      throw e;
    }
  }

  async scoreRelevance(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Evaluate Pharmacovigilance (PV) relevance (score 0-100) for these records based on potential adverse events: ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pmid: { type: Type.STRING },
                score: { type: Type.NUMBER },
                reason: { type: Type.STRING }
              },
              required: ["pmid", "score", "reason"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ pmid: r.pmid, score: 50, reason: "AI 評分暫時無法使用" }));
    }
  }

  async generateSummaries(records: any[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `請將以下文獻進行專業 PV 分析。
        1. summary_zh: 將內容翻譯為繁體中文摘要，重點放在病例描述或研究方法。
        2. conclusion_zh: 獨立提煉出該文獻的「結論」或「臨床建議」，這對藥物安全監測最重要。
        文獻資料： ${JSON.stringify(records)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pmid: { type: Type.STRING },
                summary_zh: { type: Type.STRING },
                conclusion_zh: { type: Type.STRING }
              },
              required: ["pmid", "summary_zh", "conclusion_zh"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return records.map(r => ({ pmid: r.pmid, summary_zh: "摘要生成中...", conclusion_zh: "待分析" }));
    }
  }

  async extractPVData(record: any) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `從以下內容抽取結構化 PV 數據: ${record.summary || record.title}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              product: { type: Type.STRING },
              ingredient: { type: Type.STRING },
              ae_verbatim: { type: Type.STRING },
              meddra_pt_candidate: { type: Type.STRING },
              meddra_confidence: { type: Type.NUMBER },
              seriousness: { type: Type.STRING },
              population: { type: Type.STRING },
              dosage_route: { type: Type.STRING },
              tto: { type: Type.STRING },
              outcome: { type: Type.STRING },
              causality: { type: Type.STRING },
              completeness: { type: Type.STRING }
            }
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { product: "N/A", completeness: "Missing" };
    }
  }
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  PVInput, 
  PVRecord, 
  WorkflowStep, 
  PVStructuredData
} from './types';
import { 
  db_upsert, 
  now 
} from './services/tools';
import { PVGeminiService } from './services/geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowPathIcon,
  DocumentMagnifyingGlassIcon,
  XMarkIcon,
  CircleStackIcon,
  FingerPrintIcon,
  SparklesIcon,
  GlobeAltIcon,
  BeakerIcon,
  AdjustmentsHorizontalIcon,
  ArrowTopRightOnSquareIcon,
  ArrowDownTrayIcon,
  FunnelIcon,
  MagnifyingGlassIcon,
  InboxIcon,
  TrashIcon,
  LightBulbIcon
} from '@heroicons/react/24/outline';

const gemini = new PVGeminiService();
const DB_STORAGE_KEY = 'PV_AUDITOR_MASTER_DB';

const App: React.FC = () => {
  const [input, setInput] = useState<PVInput>({
    company_product_names: ['藥品A'],
    active_ingredients: ['Fenofibrate'],
    date_window: { from: '2025-01-01', to: '2025-12-31' },
    date_logic: 'both',
    ae_strings: ['Adverse drug reactions', 'Adverse Event Reporting System', 'pharmacovigilance*'],
    optional_ae_focus_terms: [],
    exclusions: ['animal-only'],
    db_mode: 'upsert'
  });

  const [step, setStep] = useState<WorkflowStep>(WorkflowStep.IDLE);
  const [logs, setLogs] = useState<string[]>([]);
  const [records, setRecords] = useState<PVRecord[]>([]);
  const [masterDatabase, setMasterDatabase] = useState<PVRecord[]>(() => {
    const saved = localStorage.getItem(DB_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [activeTab, setActiveTab] = useState<'input' | 'review' | 'database' | 'logs'>('input');
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedRecordId, setSelectedRecordId] = useState<string | null>(null);

  const [dbFilter, setDbFilter] = useState({
    keyword: '',
    from: '',
    to: ''
  });

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  // 持久化儲存
  useEffect(() => {
    localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(masterDatabase));
  }, [masterDatabase]);

  const runWorkflow = async () => {
    setIsProcessing(true);
    setLogs([]);
    setRecords([]);
    try {
      setStep(WorkflowStep.QUERY_GEN);
      const ingredient = input.active_ingredients[0];
      const pubmedQuery = `("${ingredient}") AND (Adverse drug reactions) OR (Adverse Event Reporting System) OR (pharmacovigilance*)`;
      addLog(`[稽核] 啟動監測任務，成分：${ingredient}`);

      setStep(WorkflowStep.RSS_FETCH);
      const realResults = await gemini.performPubMedSearch(pubmedQuery, ingredient, input.date_window);

      const rawRecords: PVRecord[] = realResults.map((r: any) => ({
        id: r.pmid || `tmp-${Math.random()}`,
        source: 'pubmed',
        pmid: r.pmid,
        title: r.title,
        journal: r.journal,
        dp: r.date,
        abstract: r.summary,
        primary_link: r.url,
        quality_flags: ['PRO_VERIFIED'],
        relevance_score: 0,
        relevance_reason: '',
        is_excluded: false,
        original_search_term: ingredient // 關鍵優化：鎖定原始搜尋詞
      }));

      // 檢查是否已在資料庫中
      const freshRecords = rawRecords.filter(r => !masterDatabase.some(m => m.pmid === r.pmid));
      addLog(`[完成檢索] 找到 ${rawRecords.length} 筆，排除已存在筆數後剩餘 ${freshRecords.length} 筆新資料`);

      if (freshRecords.length > 0) {
        setStep(WorkflowStep.RELEVANCE_SCORING);
        const scores = await gemini.scoreRelevance(freshRecords);
        setStep(WorkflowStep.SUMMARIZATION);
        const summaries = await gemini.generateSummaries(freshRecords);

        const finalized = freshRecords.map(m => {
          const s = scores.find((sc: any) => sc.pmid === m.pmid);
          const sum = summaries.find((su: any) => su.pmid === m.pmid);
          return { 
            ...m, 
            relevance_score: s?.score || 50, 
            relevance_reason: s?.reason || '分析完成',
            summary_zh: sum?.summary_zh || m.abstract,
            conclusion_zh: sum?.conclusion_zh || '結論分析中'
          };
        });
        setRecords(finalized);
      } else {
        setRecords([]);
        addLog(`[提示] 本次搜尋無新文獻需要核閱。`);
      }

      setStep(WorkflowStep.IDLE);
      setActiveTab('review');
    } catch (e) {
      addLog(`[錯誤] 執行異常: ${e instanceof Error ? e.message : 'Unknown'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImport = async (record: PVRecord) => {
    if (masterDatabase.some(m => m.pmid === record.pmid)) {
      alert("此文獻 (PMID: " + record.pmid + ") 已存在於資料庫中。");
      return;
    }
    const preparedRecord = { ...record, quality_flags: [...record.quality_flags, 'DB_COMMITTED'] };
    setMasterDatabase(prev => [...prev, preparedRecord]);
    setRecords(prev => prev.filter(r => r.pmid !== record.pmid));
    setSelectedRecordId(null);
    addLog(`[資料庫] 成功匯入文獻 PMID:${record.pmid}`);
  };

  const handleDeleteFromDB = (e: React.MouseEvent, id: string) => {
    e.stopPropagation(); // 防止觸發行點擊事件
    if (window.confirm(`確定要刪除此文獻 (ID: ${id}) 嗎？\n此動作將永久移除這筆紀錄。`)) {
       setMasterDatabase(prev => prev.filter(r => r.id !== id));
       if (selectedRecordId === id) setSelectedRecordId(null);
       addLog(`[資料庫] 已手動移除文獻 ID: ${id}`);
    }
  };

  const selectedRecord = useMemo(() => 
    records.find(r => r.id === selectedRecordId) || masterDatabase.find(r => r.id === selectedRecordId)
  , [records, masterDatabase, selectedRecordId]);

  const [isExtracting, setIsExtracting] = useState(false);
  useEffect(() => {
    const triggerExtraction = async () => {
      if (selectedRecord && !selectedRecord.pv_data?.ae_verbatim && !isExtracting && !selectedRecord.is_excluded) {
        setIsExtracting(true);
        const data = await gemini.extractPVData(selectedRecord);
        const updateFn = (r: PVRecord) => {
          if (r.id !== selectedRecord.id) return r;
          return { 
            ...r, 
            pv_data: { 
              ...data,
              // 如果 AI 沒抽到成分，絕不覆蓋原始成分
              ingredient: data.ingredient && data.ingredient !== 'N/A' ? data.ingredient : r.original_search_term 
            } 
          };
        };
        setRecords(prev => prev.map(updateFn));
        setMasterDatabase(prev => prev.map(updateFn));
        setIsExtracting(false);
      }
    };
    triggerExtraction();
  }, [selectedRecordId]);

  // 超強模糊檢索邏輯
  const filteredDatabase = useMemo(() => {
    return masterDatabase.filter(r => {
      const kw = dbFilter.keyword.toLowerCase();
      // 多重欄位匹配
      const contentPool = [
        r.pmid || '',
        r.title || '',
        r.original_search_term || '',
        r.pv_data?.ingredient || '',
        r.pv_data?.product || '',
        r.journal || '',
        r.summary_zh || '',
        r.conclusion_zh || ''
      ].join(' ').toLowerCase();

      const matchKeyword = !dbFilter.keyword || contentPool.includes(kw);
      const recordDate = r.dp ? new Date(r.dp) : null;
      const matchFrom = !dbFilter.from || (recordDate && recordDate >= new Date(dbFilter.from));
      const matchTo = !dbFilter.to || (recordDate && recordDate <= new Date(dbFilter.to));

      return matchKeyword && matchFrom && matchTo;
    });
  }, [masterDatabase, dbFilter]);

  const exportToCSV = () => {
    const headers = ["PMID", "Title", "Journal", "PubDate", "SearchTerm", "AI_Ingredient", "Conclusion_ZH", "Summary_ZH"];
    const rows = filteredDatabase.map(r => [
      r.pmid, 
      `"${r.title}"`, 
      `"${r.journal}"`, 
      r.dp, 
      r.original_search_term, 
      r.pv_data?.ingredient, 
      `"${r.conclusion_zh || ''}"`,
      `"${r.summary_zh || ''}"`
    ]);
    const csvContent = "\uFEFF" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `PV_DB_Export_${now().iso_datetime.split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans">
      <div className="bg-slate-950 text-indigo-400/60 text-[10px] px-6 py-1.5 flex justify-between font-mono tracking-widest border-b border-slate-800">
        <span>PV-AUDITOR // DATA-INTEGRITY-ENABLED</span>
        <span>SYSTEM_TIME: {now().iso_datetime}</span>
      </div>

      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-5 flex justify-between items-center sticky top-0 z-30 shadow-sm">
        <div className="flex items-center gap-5">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg"><BeakerIcon className="w-7 h-7" /></div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">PV-Link Auditor</h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">專業稽核模式 (PRO-V3)</p>
          </div>
        </div>
        <button onClick={runWorkflow} disabled={isProcessing} className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-3 rounded-2xl text-sm font-black shadow-lg flex items-center gap-3 transition-all">
          <ArrowPathIcon className={`w-5 h-5 ${isProcessing ? 'animate-spin' : ''}`} />
          {isProcessing ? step : '啟動新監測任務'}
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col p-6 space-y-2">
          <button onClick={() => setActiveTab('input')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'input' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <AdjustmentsHorizontalIcon className="w-5 h-5" /> 檢索設定
          </button>
          <button onClick={() => setActiveTab('review')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'review' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <ClipboardDocumentCheckIcon className="w-5 h-5" /> 待核閱 ({records.length})
          </button>
          <button onClick={() => setActiveTab('database')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'database' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
            <CircleStackIcon className="w-5 h-5" /> 正式庫 ({masterDatabase.length})
          </button>
          <button onClick={() => setActiveTab('logs')} className="mt-auto w-full flex items-center gap-4 px-5 py-4 text-[10px] font-black uppercase text-slate-400">
            <FingerPrintIcon className="w-4 h-4" /> 系統日誌
