                    <MagnifyingGlassIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input type="text" placeholder="全域檢索: PMID、標題、成分或摘要關鍵字..." value={dbFilter.keyword} onChange={e => setDbFilter({...dbFilter, keyword: e.target.value})} className="w-full bg-white/60 border-2 border-white/50 rounded-2xl pl-12 pr-4 py-3 text-sm font-black outline-none focus:border-indigo-400/50 focus:bg-white/80 transition-all placeholder-slate-400" />
